(function(w){w.__PC_DUOC_CHUNKS=w.__PC_DUOC_CHUNKS||{};w.__PC_DUOC_CHUNKS["jci-02"]=[{"c":"AOP.03.09","ch":"AOP","t":"Bệnh viện đảm bảo chất lượng dịch vụ do các phòng xét nghiệm theo hợp đồng cung cấp.","p":"Bệnh viện có trách nhiệm đảm bảo rằng bất kỳ dịch vụ nào do các dịch vụ theo hợp đồng cung cấp đều đáp ứng mọi yêu\ncầu về cấp phép và pháp lý và đáp ứng các kỳ vọng về chất lượng do bệnh viện xây dựng.\n\nNếu bệnh viện sử dụng dịch vụ của phòng xét nghiệm theo hợp đồng, bệnh viện có trách nhiệm đảm bảo rằng phòng xét\nnghiệm theo hợp đồng được cấp phép, công nhận hoặc chứng nhận bởi các cơ quan có thẩm quyền.\n\nCác phòng xét nghiệm theo hợp đồng phải tham gia thử nghiệm năng lực để xác định kết quả của phòng xét nghiệm theo\nhợp đồng so sánh như thế nào với các phòng xét nghiệm khác sử dụng cùng phương pháp thử nghiệm.\n\nBệnh viện xác định các biện pháp để giám sát chất lượng dịch vụ do tất cả các phòng xét nghiệm theo hợp đồng cung cấp.\nCác cá nhân đủ điều kiện sẽ xem xét và hành động dựa trên kết quả giám sát chất lượng. Thông tin này được sử dụng để\nxác định các cải tiến quy trình tiềm năng và đưa ra quyết định về các hợp đồng trong tương lai với các phòng xét nghiệm\ntheo hợp đồng.\n\nĐể chắc chắn rằng phòng xét nghiệm theo hợp đồng được cấp phép và công nhận hoặc chứng nhận, và tham gia vào\nchương trình thử nghiệm năng lực bên ngoài, bệnh viện phải xin bản sao giấy phép từ cơ quan cấp phép được công nhận\nvà giấy chứng nhận hoặc thư công nhận hoặc chứng nhận từ chương trình công nhận hoặc chứng nhận phòng xét nghiệm\nđược công nhận.\n\nBệnh viện xác định các biện pháp mà phòng xét nghiệm theo hợp đồng phải thu thập và gửi đến bệnh viện, cũng như tần\nsuất dữ liệu được gửi đến bệnh viện. Các ví dụ về các biện pháp được thu thập để đánh giá các phòng xét nghiệm theo\nhợp đồng bao gồm:\n• Thời gian xử lý xét nghiệm, nghĩa là thời gian phòng xét nghiệm báo cáo kết quả sau khi nhận được mẫu\n• Báo cáo kết quả quan trọng\n• Các vấn đề với mẫu như thiếu mã định danh hoặc mẫu bị từ chối","m":[{"t":"Bệnh viện lưu giữ một bản sao giấy phép và giấy chứng nhận hoặc thư công nhận hoặc chứng nhận, từ một cơ quan có thẩm quyền được công nhận, cho tất cả các phòng xét nghiệm theo hợp đồng do bệnh viện sử dụng.","b":[]},{"t":"Bệnh viện lưu giữ tài liệu chứng minh rằng bất kỳ phòng xét nghiệm theo hợp đồng nào do bệnh viện sử dụng đều tham gia vào chương trình kiểm tra năng lực.","b":[]},{"t":"Bệnh viện xác định tần suất và loại dữ liệu kỳ vọng về hiệu suất từ các phòng xét nghiệm theo hợp đồng. (Xem thêm GLD.05.00, MEs 4 và 5)","b":[]},{"t":"Cá nhân chịu trách nhiệm về phòng xét nghiệm hoặc người được chỉ định sẽ xem xét dữ liệu hiệu suất từ các phòng xét nghiệm theo hợp đồng và thực hiện hành động dựa trên kết quả. (Xem thêm GLD.05.00, MEs 4 và 5)","b":[]},{"t":"Báo cáo hàng năm về dữ liệu từ các phòng xét nghiệm theo hợp đồng được cung cấp cho các nhà lãnh đạo chịu trách nhiệm quản lý và gia hạn hợp đồng. Đánh giá bệnh nhân (AOP) Ngân hàng máu và/hoặc dịch vụ truyền máu","b":[]}],"sec":"Dịch vụ phòng thí nghiệm"},{"c":"AOP.04.00","ch":"AOP","t":"Một hoặc nhiều cá nhân đủ tiêu chuẩn chịu trách nhiệm về ngân hàng máu và/hoặc các dịch vụ truyền máu và đảm bảo rằng các dịch vụ tuân thủ luật pháp và quy định cũng như các tiêu chuẩn thực hành được công nhận.","p":"Ngân hàng máu và/hoặc các dịch vụ truyền máu có những rủi ro riêng đối với nhân viên và bệnh nhân.\n\nNgân hàng máu và/hoặc các dịch vụ truyền máu được chỉ đạo bởi một hoặc nhiều cá nhân đủ tiêu\nchuẩn. Cá nhân này chịu trách nhiệm chuyên môn về mọi khía cạnh của ngân hàng máu và các dịch vụ\ntruyền máu được cung cấp trong bệnh viện.\n\nCác quy trình kiểm soát chất lượng cho tất cả các ngân hàng máu và các dịch vụ truyền máu được triển\nkhai và ghi chép lại để đảm bảo tính an toàn và hiệu quả của các dịch vụ ngân hàng máu và truyền máu.\nCác dịch vụ hiến máu và truyền máu được hướng dẫn bởi các luật lệ và quy định cũng như các tiêu\nchuẩn thực hành được công nhận.\n\nBệnh viện theo dõi việc sử dụng các sản phẩm máu, kết quả và tính khả dụng của các sản phẩm máu.\nNhiều bệnh viện đã triển khai các chương trình quản lý máu cho bệnh nhân để thực hiện điều này.\nCác chương trình quản lý máu cho bệnh nhân bao gồm nhiều nhân viên lâm sàng thuộc nhiều chuyên\nkhoa và thường bao gồm nhân viên quản lý chất lượng và rủi ro cũng như phòng ngừa và kiểm soát\nnhiễm trùng.\n\nBệnh viện triển khai các quy trình giám sát máu được gọi là hemovigilance. Hemovigilance bao gồm\ntoàn bộ quy trình truyền máu, từ việc hiến các sản phẩm máu cho đến việc chăm sóc theo dõi cho\nngười nhận sản phẩm máu. Giám sát bao gồm bất kỳ sự kiện bất lợi hoặc sự kiện suýt xảy ra nào liên\nquan đến ngân hàng máu và/hoặc các dịch vụ truyền máu. Khi phát hiện ra sự cố, bệnh viện có trách\nnhiệm thực hiện hành động khắc phục để ngăn ngừa sự cố tái diễn.\n\nViệc giám sát ngân hàng máu và/hoặc dịch vụ truyền máu bao gồm việc triển khai và ghi chép các quy\ntrình cung cấp máu.\n\nMột chương trình quản lý máu chính thức cho bệnh nhân có thể giúp giám sát các quy trình trên hiệu\nquả hơn. Tuy nhiên, bệnh viện xác định cách giám sát ngân hàng máu và/hoặc dịch vụ truyền máu của\nmình và cách thực hiện các thay đổi. Bệnh viện giám sát ngân hàng máu và/hoặc dịch vụ truyền máu và\ncải thiện các quy trình để thực hiện các mục tiêu sau:\n• Đảm bảo sử dụng tối ưu các sản phẩm máu.\n• Đảm bảo kết quả tối ưu cho bệnh nhân.\n• Duy trì nguồn cung cấp các sản phẩm máu.\n\nNhư đã lưu ý, các quy trình hemovigilance bao gồm việc giám sát mọi sự kiện bất lợi hoặc sự kiện suýt xảy\nra. Khi phát hiện ra sự kiện bất lợi hoặc gần xảy ra liên quan đến ngân hàng máu và/hoặc dịch vụ truyền\nmáu, sự kiện đó sẽ được điều tra và báo cáo cho tất cả các cơ quan có thẩm quyền (ví dụ: ủy ban quản lý\nrủi ro của bệnh viện hoặc ngân hàng máu địa phương hoặc khu vực).\n\nSau đó, bệnh viện thực hiện hành động khắc phục dựa trên dữ liệu giám sát để ngăn ngừa mọi sự kiện bất\nlợi hoặc gần xảy ra trong tương lai. Ví dụ về các sự kiện này bao gồm:\n• Truyền nhầm cho bệnh nhân\n• Sản phẩm máu dán nhãn sai\n• Sản phẩm máu bị nhiễm bẩn","m":[{"t":"Một hoặc nhiều cá nhân đủ tiêu chuẩn chịu trách nhiệm về ngân hàng máu và/hoặc dịch vụ truyền máu. (Xem thêm GLD.06.00, ME 1)","b":[]},{"t":"Ngân hàng máu đã triển khai và ghi chép các quy trình sau đây:","b":["Lựa chọn người hiến máu","Xét nghiệm máu để tìm bệnh","Thu thập máu","Lưu trữ máu","Kiểm tra khả năng tương thích","Phân phối máu"]},{"t":"Các biện pháp kiểm soát chất lượng cho tất cả các dịch vụ ngân hàng máu và truyền máu được thực hiện và ghi chép lại.","b":[]},{"t":"Ngân hàng máu và dịch vụ truyền máu tuân thủ các luật và quy định hiện hành và các tiêu chuẩn thực hành được công nhận.","b":[]},{"t":"Bệnh viện có quy trình theo dõi và cải thiện việc sử dụng sản phẩm máu trong toàn bệnh viện, bao gồm:","b":["Sử dụng tối ưu các sản phẩm máu","Thực hành truyền máu an toàn","Sự sẵn có của các sản phẩm máu"]},{"t":"Bệnh viện có chương trình giám sát hemovigilance để theo dõi, điều tra và báo cáo bất kỳ sự kiện bất lợi và sự kiện suýt xảy ra nào liên quan đến ngân hàng máu và/hoặc dịch vụ truyền máu. (Xem thêm QPS.03.04, ME 3)","b":[]}],"sec":"Ngân hàng máu và/hoặc dịch vụ truyền máu"},{"c":"AOP.04.01","ch":"AOP","t":"Các hướng dẫn và quy trình lâm sàng được thực hiện để xử lý và quản lý máu và các sản phẩm máu.","p":"Cần có sự giám sát thích hợp để giảm thiểu rủi ro và đảm bảo sử dụng tối ưu các sản phẩm máu. Hướng dẫn\nbổ sung cho yêu cầu quan trọng này được giải thích bên dưới.\n\nNgoài việc giám sát ngân hàng máu và các dịch vụ truyền máu, bệnh viện xác định những người được phép\ntruyền máu và các sản phẩm máu theo luật pháp và quy định của địa phương và thực hiện thống nhất các hướng\ndẫn và quy trình lâm sàng để xử lý và truyền máu và các sản phẩm máu. Bệnh viện cung cấp và lập tài liệu đào\ntạo cho tất cả nhân viên lâm sàng được phép truyền máu và các sản phẩm máu. Đào tạo này được giám sát bởi\nmột cá nhân có trình độ học vấn, kiến thức và chuyên môn liên quan đến việc truyền máu và các sản phẩm máu.\nĐào tạo thống nhất đảm bảo rằng các quy trình, quy trình và hướng dẫn lâm sàng về truyền máu được thực\nhiện trên toàn bệnh viện.\n\nĐào tạo cho nhân viên lâm sàng được phép truyền máu và các sản phẩm máu bao gồm những nội dung sau:\n• Cách xin sự đồng ý\n• Cách lấy máu và các sản phẩm máu từ ngân hàng máu hoặc khu vực lưu trữ máu\n• Cách xác minh danh tính bệnh nhân\n• Quy trình thực hiện, bao gồm các cân nhắc đặc biệt cho nhóm bệnh nhân đặc biệt (ví dụ: trẻ sơ sinh, bệnh\nnhân chấn thương)\n• Yêu cầu về tài liệu\n• Cách theo dõi và ứng phó với phản ứng truyền máu\n\nBệnh viện có quy trình theo dõi và điều tra mọi sự kiện bất lợi và sự kiện suýt xảy ra liên quan đến việc truyền\nmáu và các sản phẩm máu. Quy trình này bao gồm những nội dung sau:\n• Nhân viên lâm sàng tham gia vào sự kiện\n• Cá nhân giám sát đào tạo về việc truyền máu và các sản phẩm máu\n\nĐánh giá bệnh\nnhân (AOP)\n\n• Cá nhân(các cá nhân) giám sát ngân hàng máu và dịch vụ truyền máu\n• Cá nhân(các cá nhân) từ chương trình quản lý chất lượng và rủi ro\n• Những người khác được xác định","m":[{"t":"Bệnh viện xác định những người được phép truyền máu và các sản phẩm máu theo luật định.","b":[]},{"t":"Những cá nhân được phép truyền máu và các sản phẩm máu phải có trình độ học vấn, kiến thức và chuyên môn lâm sàng để thực hiện việc này một cách an toàn.","b":[]},{"t":"Bệnh viện cung cấp và ghi chép lại quá trình đào tạo về các hoạt động liên quan đến việc truyền máu và các sản phẩm máu.","b":[]},{"t":"Các hướng dẫn và quy trình lâm sàng được thực hiện thống nhất để xử lý và truyền máu và các sản phẩm máu.","b":[]},{"t":"Các hướng dẫn và quy trình lâm sàng giải quyết các quy trình sau:","b":["Sự đồng ý của bệnh nhân để truyền máu","Lấy máu từ ngân hàng máu hoặc khu vực lưu trữ máu","Nhận dạng bệnh nhân","Truyền máu","Theo dõi bệnh nhân","Xác định và phản ứng với các dấu hiệu phản ứng truyền máu tiềm ẩn Dịch vụ X quang và Chẩn đoán hình ảnh"]}],"sec":"Ngân hàng máu và/hoặc dịch vụ truyền máu"},{"c":"AOP.05.00","ch":"AOP","t":"Các dịch vụ chẩn đoán hình ảnh và X quang có sẵn để đáp ứng nhu cầu của bệnh nhân và tất cả các dịch vụ đều đáp ứng các tiêu chuẩn, luật pháp và quy định hiện hành của địa phương và quốc gia.","p":"Cần có các dịch vụ chẩn đoán và X quang an toàn và chính xác để đưa ra chẩn đoán và kế hoạch điều trị chính\nxác cho bệnh nhân.\n\nBệnh viện có quy trình cung cấp các dịch vụ chẩn đoán và X quang theo yêu cầu của nhóm bệnh nhân và phạm\nvi dịch vụ. Các dịch vụ chẩn đoán và X quang đáp ứng mọi tiêu chuẩn, luật, quy định và tiêu chuẩn chuyên\nmôn của địa phương và quốc gia hiện hành.\n\nCác dịch vụ chẩn đoán và X quang, bao gồm cả các dịch vụ cần thiết cho trường hợp khẩn cấp, có thể được\ncung cấp trong bệnh viện, theo thỏa thuận với một tổ chức khác hoặc cả hai. Các dịch vụ chẩn đoán và X\nquang\ncó sẵn sau giờ làm việc bình thường cho các trường hợp khẩn cấp. Ngoài ra, bệnh viện có thể xác định và liên\nhệ với các chuyên gia\ntrong các lĩnh vực chẩn đoán chuyên khoa và bệnh viện duy trì danh sách các chuyên gia như vậy. Ví dụ về các\nlĩnh vực chuyên khoa\nnày bao gồm:\n•\nVật lý bức xạ\n•\nXạ trị ung thư\n•\nY học hạt nhân\n•\nX quang can thiệp\n•\nX quang can thiệp thần kinh\n•\nThông tim\n\nCác nguồn bên ngoài thuận tiện cho bệnh nhân tiếp cận và các báo cáo được nhận kịp thời để hỗ trợ việc\nchăm sóc bệnh nhân. Bệnh viện lựa chọn các nguồn bên ngoài dựa trên khuyến nghị của cá nhân chịu trách\nnhiệm về dịch vụ chẩn đoán hình ảnh và X quang.\n\nĐánh giá bệnh\nnhân (AOP)\n\nCác nguồn dịch vụ chẩn đoán hình ảnh và X quang bên ngoài đáp ứng các luật và quy định hiện hành và có hồ\nsơ chấp nhận được về các dịch vụ chính xác, kịp thời. Bệnh nhân được thông báo khi một nguồn dịch vụ bên\nngoài thuộc sở hữu của bác sĩ giới thiệu.","m":[{"t":"Dịch vụ chẩn đoán hình ảnh và X quang đáp ứng các tiêu chuẩn chuyên môn hiện hành theo luật pháp và quy định của địa phương và quốc gia.","b":[]},{"t":"Các dịch vụ chẩn đoán hình ảnh và X quang có sẵn để đáp ứng các nhu cầu liên quan đến nhóm bệnh nhân của bệnh viện, phạm vi dịch vụ và nhu cầu cấp cứu, bao gồm cả ngoài giờ làm việc bình thường.","b":[]},{"t":"Bệnh viện duy trì danh sách các chuyên gia trong các lĩnh vực chẩn đoán chuyên khoa và đảm bảo rằng danh sách này có thể được nhân viên có nhu cầu truy cập.","b":[]},{"t":"Các nguồn bên ngoài được lựa chọn dựa trên khuyến nghị của cá nhân chịu trách nhiệm về dịch vụ chẩn đoán hình ảnh và X quang và có hồ sơ chấp nhận được về hiệu suất kịp thời và tuân thủ các luật và quy định hiện hành.","b":[]}],"sec":"Dịch vụ X quang và Chẩn đoán hình ảnh"},{"c":"AOP.05.01","ch":"AOP","t":"Một hoặc nhiều cá nhân có trình độ chịu trách nhiệm quản lý các dịch vụ chẩn đoán hình ảnh và X quang, và những cá nhân có trình độ và kinh nghiệm phù hợp sẽ thực hiện các nghiên cứu chẩn đoán hình ảnh, giải thích kết quả và báo cáo kết quả.","p":"Dịch vụ X quang và chẩn đoán hình ảnh được quản lý bởi một cá nhân có trình độ chuyên môn để đảm bảo\nrằng các dịch vụ đáp ứng nhu cầu, luật pháp và quy định của bệnh nhân. Cần có nhân viên X quang và chẩn\nđoán hình ảnh đủ trình độ để thực hiện các xét nghiệm và giải thích kết quả để đảm bảo rằng dữ liệu thu thập\nđược thông qua các dịch vụ này là chính xác.\n\nDịch vụ X quang và chẩn đoán hình ảnh, được cung cấp tại bất kỳ địa điểm nào trong bệnh viện, đều do một\ncá nhân có trình độ chuyên môn được ghi chép lại, đào tạo và kinh nghiệm, phù hợp với luật pháp và quy định\nhiện hành chỉ đạo. Cá nhân này chịu trách nhiệm chuyên môn đối với cơ sở X quang và chẩn đoán hình ảnh,\nthiết bị và các dịch vụ được cung cấp.\n\nKhi cá nhân này cung cấp tư vấn lâm sàng hoặc ý kiến y khoa, họ là bác sĩ, tốt nhất là bác sĩ X quang. Khi cung\ncấp các dịch vụ đặc biệt, họ được chỉ đạo bởi những cá nhân có trình độ phù hợp. Ví dụ về các dịch vụ đặc biệt\nbao gồm:\n• Xạ trị\n• Y học hạt nhân\n• X quang can thiệp\n• X quang can thiệp thần kinh\n• Thông tim\n\nTrách nhiệm của người đứng đầu khoa X quang và chẩn đoán hình ảnh bao gồm:\n• Phát triển, triển khai và duy trì các chính sách và quy trình\n• Giám sát các nhiệm vụ hành chính\n• Giám sát kiểm soát chất lượng\n• Phát triển và triển khai chương trình tuyển dụng nhân sự\n• Đề xuất các nguồn dịch vụ X quang và chẩn đoán hình ảnh bên ngoài\n• Giám sát và xem xét tất cả các dịch vụ X quang và chẩn đoán hình ảnh\n\nBệnh viện xác định nhân viên X quang và chẩn đoán hình ảnh nào thực hiện các nghiên cứu chẩn đoán và hình\nảnh; có đủ trình độ để giải thích kết quả hoặc xác minh và báo cáo kết quả; và chỉ đạo hoặc giám sát các quy\ntrình.\n\nNhân viên giám sát và nhân viên kỹ thuật có đào tạo, kinh nghiệm và kỹ năng phù hợp và đầy đủ và được định\nhướng vào trách nhiệm của họ. Các thành viên nhân viên kỹ thuật được giao nhiệm vụ công việc phù hợp với\nđào tạo và kinh nghiệm của họ.\n\nNgoài ra, phải có đủ số lượng nhân viên để thực hiện, giải thích và báo cáo các nghiên cứu trong khung thời gian\ndo chính sách của bệnh viện quy định và cung cấp đủ nhân viên cần thiết trong suốt thời gian hoạt động và trong\ncác trường hợp khẩn cấp.","m":[{"t":"Các dịch vụ chẩn đoán hình ảnh và X quang được chỉ đạo bởi một hoặc nhiều cá nhân có trình độ. (Xem thêm GLD.06.00, ME 1)","b":[]},{"t":"Trách nhiệm của cá nhân quản lý dịch vụ chẩn đoán hình ảnh và X quang bao gồm những điều sau:","b":["Phát triển, triển khai và duy trì các chính sách và quy trình","Giám sát các nhiệm vụ hành chính","Giám sát kiểm soát chất lượng","Phát triển và triển khai chương trình tuyển dụng nhân sự","Đề xuất các nguồn dịch vụ chẩn đoán hình ảnh và X quang bên ngoài","Giám sát và xem xét tất cả các dịch vụ chẩn đoán hình ảnh và X quang"]},{"t":"Nhân viên có trình độ và kinh nghiệm phù hợp thực hiện các nghiên cứu chẩn đoán hình ảnh.","b":[]},{"t":"Nhân viên có trình độ và kinh nghiệm phù hợp giải thích kết quả nghiên cứu và xác minh và báo cáo kết quả trong khung thời gian do chính sách của bệnh viện quy định.","b":[]},{"t":"Có đủ số lượng nhân viên để đáp ứng nhu cầu của bệnh nhân và phạm vi dịch vụ của bệnh viện.","b":[]},{"t":"Nhân viên giám sát chẩn đoán hình ảnh và X quang có trình độ và kinh nghiệm phù hợp cho vai trò này.","b":[]}],"sec":"Dịch vụ X quang và Chẩn đoán hình ảnh"},{"c":"AOP.05.02","ch":"AOP","t":"Một chương trình an toàn về bức xạ và/hoặc chẩn đoán hình ảnh dành cho bệnh nhân, nhân viên và khách thăm được triển khai và tuân thủ các tiêu chuẩn, luật và quy định chuyên môn hiện hành.","p":"Tiếp xúc với bức xạ có thể gây ra nguy cơ tiềm ẩn gây tổn thương lâu dài, do đó bệnh viện có trách nhiệm triển\nkhai chương trình an toàn bức xạ để bảo vệ bệnh nhân, nhân viên và khách thăm khỏi việc tiếp xúc với bức xạ\nkhông cần thiết hoặc quá mức.\n\nRủi ro gây tổn thương lâu dài phụ thuộc vào liều lượng bức xạ được truyền đi và thời gian cũng như tần suất\ntiếp xúc với bức xạ. Liều lượng bức xạ càng cao thì nguy cơ gây tổn thương lâu dài càng lớn và liều lượng lặp lại\ncó tác động tích lũy gây ra rủi ro lớn hơn. Các thủ thuật chẩn đoán thường liên quan nhất đến liều lượng bức xạ\ncó thể tránh được là chụp cắt lớp vi tính (CT), y học hạt nhân và chụp huỳnh quang. Chương trình an toàn bức\nxạ rất quan trọng trong việc sử dụng an toàn bức xạ ion hóa, bao gồm vật liệu phóng xạ (RAM) và máy tạo bức\nxạ.\n\nCác nhà cung cấp dịch vụ chăm sóc sức khỏe cân nhắc giữa nhu cầu y tế của việc tiếp xúc với bức xạ để chẩn\nđoán hoặc điều trị so với các rủi ro. Cần tránh tiếp xúc với bức xạ không cần thiết. Bệnh viện tuân thủ các nguyên\ntắc của ALARA (duy trì tất cả các mức tiếp xúc với bức xạ ở mức thấp nhất có thể đạt được).\n\nChẩn đoán hình ảnh, chẳng hạn như chụp cộng hưởng từ (MRI) và siêu âm (US), không sử dụng bức xạ ion hóa,\ndo đó không có rủi ro từ bức xạ. Có những dịch vụ chẩn đoán hình ảnh liên quan đến rủi ro khác cần được giải\nquyết. Các mối nguy hiểm từ MRI bao gồm:\n• Tiếp xúc với từ trường mạnh\n• Có khí lạnh được sử dụng để làm mát nam châm của MRI\n• Tiếp xúc với tiếng ồn\n\nBệnh viện có chương trình an toàn chẩn đoán hình ảnh và bức xạ bao gồm tất cả các thành phần của dịch vụ\nchẩn đoán hình ảnh và X quang của bệnh viện, bao gồm cả xạ trị ung thư và phòng thông tim. Chương trình an\ntoàn giải quyết các rủi ro và mối nguy hiểm gặp phải và thực hiện các biện pháp phòng ngừa và thực hành an toàn\ncho nhân viên chẩn đoán hình ảnh và X quang, bệnh nhân và khách đến thăm. Chương trình được phối hợp với\ncác chương trình quản lý cơ sở và phòng ngừa và kiểm soát nhiễm trùng của bệnh viện.\n\nNhư đã lưu ý, bệnh viện tuân thủ các nguyên tắc của ALARA (duy trì mọi mức phơi nhiễm bức xạ ở mức thấp\nnhất có thể), bao gồm:\n•\nGiảm thiểu thời gian nhân viên, bệnh nhân và khách thăm tiếp xúc với bức xạ\n•\nTăng khoảng cách giữa nguồn bức xạ và bất kỳ nhân viên, bệnh nhân và khách thăm nào\n•\nSử dụng chì hoặc các tấm chắn khác để giảm phơi nhiễm với bức xạ\n\nBệnh viện phải thực hiện các biện pháp để giải quyết những mối nguy hiểm này từ chẩn đoán hình ảnh. Ví dụ,\ncác biện pháp an toàn MRI có thể bao gồm những điều sau:\n•\nĐánh dấu rõ ràng các khu vực an toàn trong khu vực MRI để chỉ ra những người có thể tiếp cận và những\nbiện pháp phòng ngừa an toàn nào là cần thiết trong mỗi khu vực\n•\nĐảm bảo thông gió thích hợp và đào tạo nhân viên phù hợp để giải quyết các mối nguy hiểm liên quan\nđến khí lạnh\n•\nBảo vệ tai để giảm sự khó chịu và tác hại từ tiếng ồn trong quá trình kiểm tra MRI\n•\nHạn chế chỉ những nhân viên được ủy quyền và những bệnh nhân đi cùng những nhân viên đó mới được\ntiếp cận khu vực từ trường MRI\n•\nĐặt biển báo trong và xung quanh khu vực để xác định các mối nguy hiểm\n•\nHoàn thành danh sách kiểm tra trước khi chụp để xác định bất kỳ rủi ro hoặc tiêu chí loại trừ nào đối với\nnhững bệnh nhân đang chụp MRI (ví dụ: cấy ghép kim loại, mảnh đạn, máy tạo nhịp tim)\n•\nĐảm bảo chỉ có thiết bị đặc biệt không chứa sắt từ mới được đưa vào môi trường MRI\n\nChương trình quản lý an toàn bức xạ bao gồm những điều sau:\n•\nTuân thủ các tiêu chuẩn, luật và quy định chuyên môn hiện hành\n•\nĐịnh hướng cho tất cả nhân viên chẩn đoán hình ảnh và X quang về các quy trình và thực hành an toàn\n•\nĐào tạo và giáo dục liên tục về các quy trình mới, thiết bị mới và thiết bị mới mua hoặc các vật liệu nguy\nhiểm được công nhận\n•\nCó sẵn thiết bị và dụng cụ bảo vệ an toàn phù hợp với các hoạt động và mối nguy hiểm gặp phải; trong\nkhoa X quang, các thiết bị và dụng cụ bảo vệ bao gồm tạp dề chì, lớp lót chì trong tường và huy hiệu bức\nxạ (dành cho nhân viên), trong số những thứ khác.\n•\nTuân thủ các tiêu chuẩn giải quyết các chương trình quản lý cơ sở và phòng ngừa và kiểm soát nhiễm\ntrùng","m":[{"t":"Một chương trình an toàn về bức xạ và/hoặc chẩn đoán hình ảnh dành cho bệnh nhân, nhân viên và khách thăm được triển khai và tuân thủ các tiêu chuẩn, luật và quy định chuyên môn hiện hành.","b":[]},{"t":"Nhân viên X quang và chẩn đoán hình ảnh được định hướng theo các yêu cầu về an toàn và được đào tạo và giáo dục liên tục về bất kỳ quy trình, thiết bị và vật liệu nguy hiểm mới nào. (Xem thêm SQE.01.07, ME 1)","b":[]},{"t":"Thiết bị và dụng cụ bảo vệ an toàn phù hợp với các hoạt động và mối nguy hiểm gặp phải từ bức xạ và chẩn đoán hình ảnh được cung cấp cho nhân viên, bệnh nhân và khách thăm, và trong khu vực cung cấp dịch vụ X quang và chẩn đoán hình ảnh.","b":[]},{"t":"Giáo dục về an toàn bức xạ bao gồm các nguyên tắc của ALARA và việc triển khai các giao thức xác định liều bức xạ tối đa cho từng loại nghiên cứu.","b":[]},{"t":"Các mối nguy hiểm từ chụp cộng hưởng từ được giải quyết bằng cách sử dụng các tiêu chuẩn của ngành và các hướng dẫn dựa trên bằng chứng.","b":[]},{"t":"Bệnh viện chỉ định một cá nhân làm nhân viên an toàn bức xạ, người chịu trách nhiệm về các nội dung sau:","b":["Đảm bảo các dịch vụ X quang được cung cấp theo đúng luật pháp, quy định và chính sách của tổ chức","Giám sát việc tuân thủ các thông lệ an toàn bức xạ đã thiết lập (bao gồm giám sát việc giám sát liều lượng)"]},{"t":"Chương trình an toàn bức xạ và/hoặc chẩn đoán hình ảnh là một phần của các chương trình quản lý cơ sở và phòng ngừa và kiểm soát nhiễm trùng của tổ chức và cung cấp báo cáo cho các chương trình đó ít nhất hàng năm và khi xảy ra bất kỳ sự kiện an toàn và sự kiện kiểm soát nhiễm trùng nào.","b":[]}],"sec":"Dịch vụ X quang và Chẩn đoán hình ảnh"},{"c":"AOP.05.03","ch":"AOP","t":"Kết quả nghiên cứu chẩn đoán hình ảnh và X quang có sẵn kịp thời theo quy định của chính sách bệnh viện.","p":"Việc báo cáo kịp thời kết quả chụp X-quang và chẩn đoán hình ảnh là rất quan trọng để đánh giá và chẩn đoán bệnh nhân\nkịp thời.\n\nBệnh viện xác định khung thời gian để báo cáo kết quả chụp X-quang chẩn đoán và chẩn đoán hình ảnh. Kết quả được báo\ncáo trong khung thời gian dựa trên nhu cầu của bệnh nhân, dịch vụ được cung cấp và nhu cầu của nhân viên lâm sàng. Bao\ngồm cả nhu cầu chụp X-quang khẩn cấp hoặc chụp X-quang sau giờ làm việc và chụp X-quang cuối tuần.\n\nBệnh viện theo dõi xem kết quả chụp X-quang và chẩn đoán hình ảnh có được báo cáo trong khung thời gian hay không. Kết\nquả từ các nghiên cứu chụp X-quang và chẩn đoán hình ảnh khẩn cấp hoặc cấp cứu được đặc biệt chú ý trong quá trình đo\nlường chất lượng. Nếu kết quả không được báo cáo theo khung thời gian của bệnh viện, bệnh viện sẽ xác định các rào cản\nđể đạt được mục tiêu này và thực hiện các hành động khắc phục.\n\nCác nghiên cứu chụp X-quang và chẩn đoán hình ảnh do các nhà thầu dịch vụ bên ngoài thực hiện được báo cáo theo chính\nsách của bệnh viện hoặc yêu cầu hợp đồng.","m":[{"t":"Bệnh viện có chính sách bằng văn bản thiết lập thời gian báo cáo dự kiến cho kết quả chụp X-quang chẩn đoán.","b":[]},{"t":"Bệnh viện theo dõi xem kết quả chụp X-quang và chẩn đoán khẩn cấp hay cấp cứu có được báo cáo trong khung thời gian dự kiến hay không.","b":[]},{"t":"Bệnh viện theo dõi xem kết quả chụp X-quang và chẩn đoán thường quy có được báo cáo trong khung thời gian dự kiến hay không.","b":[]},{"t":"Khi kết quả chụp X-quang và chẩn đoán không được báo cáo trong khung thời gian dự kiến, bệnh viện sẽ thực hiện hành động khắc phục.","b":[]}],"sec":"Dịch vụ X quang và Chẩn đoán hình ảnh"},{"c":"AOP.05.04","ch":"AOP","t":"Tất cả các thiết bị được sử dụng để tiến hành các nghiên cứu chẩn đoán hình ảnh và X-quang đều được kiểm tra, bảo trì và hiệu chuẩn thường xuyên, đồng thời có hồ sơ ghi chép phù hợp cho các hoạt động này.","p":"Việc bảo trì và hiệu chuẩn đúng cách các thiết bị X quang và chẩn đoán hình ảnh là điều cần thiết để đảm bảo độ chính xác\ncủa kết quả xét nghiệm.\n\nNhân viên X quang và chẩn đoán hình ảnh đảm bảo rằng tất cả các thiết bị được sử dụng cho các chương trình X quang và\nchẩn đoán hình ảnh đều hoạt động bình thường. Bệnh viện có một chương trình quản lý các thiết bị X quang và chẩn đoán\nhình ảnh. Tần suất kiểm tra, bảo trì và hiệu chuẩn được hoàn thành theo hướng dẫn của nhà sản xuất hoặc thường xuyên\nhơn dựa trên việc sử dụng thiết bị và lịch sử dịch vụ được ghi chép lại.\n\nChương trình quản lý các thiết bị X quang và chẩn đoán hình ảnh bao gồm các nội dung sau:\n•\nLựa chọn và mua các thiết bị X quang và chẩn đoán hình ảnh và thiết bị y tế\n•\nXác định và kiểm kê các thiết bị X quang và chẩn đoán hình ảnh\n•\nĐánh giá việc sử dụng các thiết bị X quang và chẩn đoán hình ảnh thông qua việc kiểm tra, thử nghiệm, hiệu\nchuẩn và bảo trì\n•\nTheo dõi và hành động đối với các thông báo nguy hiểm, thu hồi, các sự cố, vấn đề và lỗi có thể báo cáo của thiết\nbị X quang và chẩn đoán hình ảnh\n•\nGhi lại chương trình quản lý","m":[{"t":"Bệnh viện xây dựng và triển khai chương trình bằng văn bản để quản lý thiết bị chẩn đoán hình ảnh và X quang, bao gồm cách lựa chọn và mua thiết bị X quang.","b":[]},{"t":"Có một bản kiểm kê được lập thành văn bản về tất cả các thiết bị chẩn đoán hình ảnh và X quang. (Xem thêm FMS.07.00, ME 2)","b":[]},{"t":"Thiết bị chẩn đoán hình ảnh và X quang được kiểm tra và thử nghiệm khi mới và theo tuổi, cách sử dụng và khuyến nghị của từng nhà sản xuất; các cuộc kiểm tra được ghi lại.","b":[]},{"t":"Thiết bị chẩn đoán hình ảnh và X quang được hiệu chuẩn và bảo trì theo khuyến nghị của từng nhà sản xuất, và việc hiệu chuẩn và bảo trì được ghi lại.","b":[]},{"t":"Bệnh viện có một hệ thống để theo dõi và hành động đối với các thông báo nguy hiểm, thu hồi, sự cố cần báo cáo, vấn đề và lỗi của thiết bị chẩn đoán hình ảnh và X quang. (Xem thêm FMS.07.01, ME 1)","b":[]}],"sec":"Đánh giá bệnh"},{"c":"AOP.05.05","ch":"AOP","t":"Bệnh viện đã triển khai các quy trình kiểm soát chất lượng dịch vụ chẩn đoán hình ảnh và X quang.","p":"Các quy trình kiểm soát chất lượng được thiết kế tốt và thử nghiệm năng lực là điều cần thiết để cung\ncấp các dịch vụ chẩn đoán hình ảnh và X quang chính xác. Kiểm soát chất lượng cũng bao gồm giám sát\nhàng ngày để đảm bảo rằng việc thử nghiệm được hoàn thành theo đúng quy trình. Các hành động khắc\nphục nhanh chóng được thực hiện khi phát hiện ra các thiếu sót.\n\nCác quy trình kiểm soát chất lượng bao gồm:\n•\nXem xét chất lượng hình ảnh\n•\nĐộ chính xác của việc giải thích hình ảnh\n•\nGiám sát kết quả hàng ngày bởi đội ngũ nhân viên chẩn đoán hình ảnh và X quang có trình độ\n•\nHành động khắc phục nhanh chóng khi phát hiện ra thiếu sót\n•\nGhi chép kết quả và hành động khắc phục","m":[{"t":"Bệnh viện thiết lập và triển khai chương trình kiểm soát chất lượng bằng văn bản cho các dịch vụ chẩn đoán hình ảnh và X quang.","b":[]},{"t":"Kiểm soát chất lượng bao gồm xác nhận các phương pháp thử nghiệm về độ chính xác và độ tin cậy.","b":[]},{"t":"Kiểm soát chất lượng bao gồm việc sửa chữa nhanh chóng và lập hồ sơ khi phát hiện ra thiếu sót.","b":[]}],"sec":"Đánh giá bệnh"},{"c":"AOP.05.06","ch":"AOP","t":"Bệnh viện đảm bảo chất lượng dịch vụ do tất cả các nguồn dịch vụ chẩn đoán hình ảnh và X quang bên ngoài ký hợp đồng cung cấp.","p":"Bệnh viện có trách nhiệm đảm bảo rằng bất kỳ dịch vụ nào do dịch vụ theo hợp đồng cung cấp đều đáp ứng mọi yêu\ncầu về cấp phép và pháp lý và đáp ứng các kỳ vọng về chất lượng do bệnh viện đưa ra.\n\nNếu bệnh viện sử dụng dịch vụ của dịch vụ chẩn đoán hình ảnh hoặc X quang theo hợp đồng, bệnh viện có trách nhiệm\nđảm bảo rằng dịch vụ chẩn đoán hình ảnh hoặc X quang đó được cấp phép và công nhận hoặc chứng nhận bởi các cơ\nquan có thẩm quyền.\n\nBệnh viện xác định các biện pháp để giám sát chất lượng dịch vụ do tất cả các dịch vụ chẩn đoán hình ảnh và X quang\ntheo hợp đồng cung cấp. Những cá nhân đủ điều kiện sẽ xem xét và hành động dựa trên kết quả giám sát chất lượng.\n\nĐánh giá bệnh\nnhân (AOP)\n\nThông tin này được sử dụng để xác định những cải tiến quy trình tiềm năng và đưa ra quyết định về các hợp\nđồng trong tương lai với các dịch vụ chẩn đoán hình ảnh và X quang đã ký hợp đồng.\n\nBệnh viện xác định các biện pháp mà dịch vụ chẩn đoán hình ảnh hoặc X quang theo hợp đồng được yêu cầu thu thập và\ngửi đến bệnh viện, cũng như tần suất dữ liệu được gửi đến bệnh viện. Các ví dụ về các biện pháp được thu thập để đánh\ngiá dịch vụ chẩn đoán hình ảnh hoặc X quang theo hợp đồng bao gồm:\n•\nThời gian xử lý xét nghiệm, nghĩa là thời gian cần thiết để X quang hoặc Chẩn đoán hình ảnh nhận được lệnh, lấy\nhình ảnh và báo cáo kết quả\n•\nBáo cáo kết quả quan trọng\n•\nCác vấn đề về hình ảnh như thiếu mã định danh hoặc từ chối mẫu","m":[{"t":"Bệnh viện lưu giữ một bản sao giấy phép từ một cơ quan có thẩm quyền được công nhận cho tất cả các dịch vụ chẩn đoán hình ảnh và X quang theo hợp đồng do bệnh viện sử dụng.","b":[]},{"t":"Bệnh viện lưu giữ một bản sao giấy chứng nhận hoặc thư công nhận hoặc chứng nhận từ một cơ quan có thẩm quyền được công nhận cho tất cả các dịch vụ chẩn đoán hình ảnh và X quang theo hợp đồng do bệnh viện sử dụng.","b":[]},{"t":"Bệnh viện xác định tần suất và loại dữ liệu chất lượng từ các dịch vụ chẩn đoán hình ảnh và X quang theo hợp đồng. (Xem thêm GLD.05.00, MEs 4 và 5)","b":[]},{"t":"Cá nhân chịu trách nhiệm về các dịch vụ chẩn đoán hình ảnh và X quang hoặc người được chỉ định xem xét dữ liệu đo lường hiệu suất từ các dịch vụ chẩn đoán hình ảnh và X quang theo hợp đồng và thực hiện hành động dựa trên kết quả. (Xem thêm GLD.05.00, MEs 4 và 5)","b":[]},{"t":"Báo cáo hàng năm về dữ liệu từ các dịch vụ chẩn đoán hình ảnh và X quang theo hợp đồng được cung cấp cho những người đưa ra quyết định về quản lý và gia hạn hợp đồng. Dịch vụ Y học hạt nhân","b":[]}],"sec":"Đánh giá bệnh"},{"c":"AOP.06.00","ch":"AOP","t":"Khi áp dụng, bệnh viện thiết lập và thực hiện chương trình an toàn y học hạt nhân tuân thủ các tiêu chuẩn, luật và quy định chuyên môn hiện hành.","p":"Y học hạt nhân là một nhánh của hình ảnh y khoa và điều trị sử dụng một lượng nhỏ vật liệu phóng xạ, được gọi là dược\nphẩm phóng xạ, để chẩn đoán và điều trị nhiều bệnh khác nhau. Do sử dụng bức xạ, các tiêu chuẩn và hướng dẫn an\ntoàn nghiêm ngặt được đưa ra để đảm bảo sức khỏe của bệnh nhân, chuyên gia chăm sóc sức khỏe và công chúng nói\nchung.\n\nCác hoạt động y học hạt nhân được quản lý bởi nhiều tổ chức quốc gia và quốc tế, chẳng hạn như Cơ quan Năng lượng\nNguyên tử Quốc tế (IAEA), Ủy ban Quản lý Hạt nhân (NRC) tại Hoa Kỳ và Cơ quan Dược phẩm Châu Âu (EMA) tại\nChâu Âu. Các cơ quan này thiết lập và thực thi các tiêu chuẩn an toàn, bao gồm các yêu cầu cấp phép, hướng dẫn đào tạo\nvà quy định về thiết bị. Các chuyên gia y tế làm việc với vật liệu phóng xạ trong y học hạt nhân, chẳng hạn như bác sĩ y\nhọc hạt nhân, bác sĩ X quang và kỹ thuật viên, phải trải qua khóa đào tạo chuyên sâu để đảm bảo rằng họ có đủ\nkiến thức và kỹ năng cần thiết để xử lý vật liệu phóng xạ một cách an toàn. Họ phải được đào tạo về an toàn bức xạ, bảo\nvệ bức xạ và xử lý và thải bỏ chất thải phóng xạ đúng cách.\n\nCác cơ sở y học hạt nhân được thiết kế để giảm thiểu tiếp xúc với bức xạ đối với nhân viên và công chúng. Các vật liệu\nche chắn, chẳng hạn như chì và bê tông, được sử dụng để chứa bức xạ trong các khu vực được chỉ định. Cần có hệ thống\nthông gió, thiết bị giám sát và rào chắn bức xạ phù hợp để đảm bảo an toàn. Các chương trình đảm bảo chất lượng được\nthiết lập để đảm bảo tính chính xác và an toàn của các quy trình y học hạt nhân.\n\nĐánh giá bẹnh\nnhân (AOP)\n\nCác biện pháp hiệu chuẩn thiết bị, kiểm tra hiệu suất và kiểm soát chất lượng thường xuyên được thực\nhiện để duy trì độ tin cậy và hiệu quả của thiết bị chụp ảnh và điều trị.\n\nBệnh nhân được lên lịch thực hiện các thủ thuật y học hạt nhân sẽ nhận được hướng dẫn cụ thể về việc\nchuẩn bị, chẳng hạn như yêu cầu nhịn ăn hoặc ngừng một số loại thuốc nhất định. Bệnh nhân được giáo\ndục về các lợi ích, rủi ro và biện pháp phòng ngừa an toàn liên quan đến thủ thuật. Có được sự đồng ý có\nhiểu biết và giải quyết các mối quan tâm hoặc câu hỏi của bệnh nhân. Mức độ phơi nhiễm bức xạ được\ntheo dõi đối với cả bệnh nhân và các chuyên gia chăm sóc sức khỏe tham gia vào các thủ thuật y học hạt\nnhân. Máy đo liều cá nhân được đeo để đo lượng bức xạ tiếp nhận. Việc theo dõi thường xuyên giúp\nđảm bảo rằng liều bức xạ nằm trong giới hạn cho phép và các biện pháp an toàn thích hợp được tuân thủ.\n\nXử lý chất thải phóng xạ đúng cách là rất quan trọng để ngăn ngừa ô nhiễm môi trường và đảm bảo an\ntoàn công cộng. Các cơ sở y học hạt nhân tuân thủ các giao thức nghiêm ngặt về việc thu gom, lưu trữ và\nxử lý vật liệu và chất thải phóng xạ. Các thủ tục này tuân thủ luật pháp, quy định và hướng dẫn của địa\nphương.","m":[{"t":"Một hoặc nhiều cá nhân đủ tiêu chuẩn chịu trách nhiệm giám sát các dịch vụ y học hạt nhân và các nhân viên có liên quan được đào tạo, đủ tiêu chuẩn và được cấp chứng chỉ phù hợp để thực hiện các vai trò tương ứng của họ trong các quy trình và an toàn y học hạt nhân.","b":[]},{"t":"Bệnh viện thực hiện các giao thức an toàn bức xạ, bao gồm việc sử dụng tấm chắn thích hợp, thiết bị bảo vệ cá nhân (PPE) và thiết bị theo dõi cho cả bệnh nhân và nhân viên.","b":[]},{"t":"Liều bức xạ được sử dụng cho bệnh nhân được tối ưu hóa cho mục đích chẩn đoán và điều trị và quy trình bao gồm việc theo dõi và giảm thiểu phơi nhiễm bức xạ trong khi thu thập thông tin chẩn đoán hoặc hiệu quả điều trị cần thiết.","b":[]},{"t":"Việc mua sắm, lưu trữ, xử lý và thải bỏ dược phẩm phóng xạ tuân thủ luật pháp, quy định, tiêu chuẩn chuyên môn và hướng dẫn của nhà sản xuất.","b":[]},{"t":"Bệnh nhân và gia đình được thông báo về các quy trình và biện pháp phòng ngừa an toàn. Gây mê và chăm sóc phẫu thuật (ASC) Gây mê và chăm sóc phẫu thuật Tổng quan Việc sử dụng gây mê phẫu thuật, an thần thủ thuật và can thiệp phẫu thuật là những quy trình phổ biến và phức tạp trong một tổ chức chăm sóc sức khỏe. Chúng đòi hỏi phải đánh giá bệnh nhân toàn diện và đầy đủ, lập kế hoạch chăm sóc tích hợp, theo dõi bệnh nhân liên tục và chuyển viện theo tiêu chí để tiếp tục chăm sóc, phục hồi chức năng và cuối cùng là chuyển viện và xuất viện. Vì phản ứng của từng bệnh nhân có thể thay đổi theo chuỗi liên tục đó, nên việc sử dụng gây mê toàn thân và an thần thủ thuật phải được tổ chức theo cách tích hợp. Do đó, chương này đề cập đến an thần/giảm đau vừa phải và sâu đến gây mê toàn thân khi phản xạ bảo vệ của bệnh nhân cần thiết cho đường thở thông thoáng và duy trì chức năng hô hấp gặp nguy cơ. Chương này không đề cập đến việc sử dụng an thần tối thiểu cho mục đích giảm lo âu hoặc an thần cần thiết trong đơn vị chăm sóc đặc biệt để dung nạp máy thở. An thần theo thủ thuật được định nghĩa là việc sử dụng thuốc an thần hoặc thuốc gây phân ly có hoặc không có thuốc giảm đau cho một cá nhân, trong bất kỳ hoàn cảnh nào, theo bất kỳ con đường nào, để tạo ra trạng thái ý thức thay đổi cho phép bệnh nhân chịu đựng các thủ thuật gây đau đớn hoặc khó chịu trong khi vẫn duy trì chức năng tim mạch. Định nghĩa về bốn mức độ an thần và gây mê bao gồm: An thần tối thiểu (giải lo âu): Trạng thái do thuốc gây ra trong đó bệnh nhân phản ứng bình thường với các lệnh bằng lời nói. Mặc dù chức năng nhận thức và phối hợp có thể bị suy giảm, nhưng chức năng hô hấp và tim mạch không bị ảnh hưởng. An thần/giảm đau vừa phải (“an thần có ý thức”): Sự ức chế ý thức do thuốc gây ra trong đó bệnh nhân phản ứng có chủ đích với các lệnh bằng lời nói, đơn lẻ hoặc kèm theo kích thích xúc giác nhẹ. Việc rút phản xạ khỏi kích thích gây đau không được coi là phản ứng có chủ đích. Không cần can thiệp để duy trì đường thở thông thoáng và thông khí tự nhiên là đủ. Chức năng tim mạch thường được duy trì mà không cần các biện pháp hỗ trợ. Chăm sóc gây mê có giám sát (“MAC”) không mô tả mức độ liên tục của an thần, mà mô tả dịch vụ gây mê cụ thể do bác sĩ gây mê đủ tiêu chuẩn thực hiện cho một thủ thuật chẩn đoán hoặc điều trị. Chỉ định cho chăm sóc gây mê có giám sát bao gồm nhu cầu giảm đau và an thần ở mức độ sâu hơn mức có thể cung cấp bằng an thần vừa phải, bao gồm khả năng chuyển sang gây mê toàn thân hoặc gây tê vùng. An thần/giảm đau sâu: Tình trạng suy giảm ý thức do thuốc gây ra, trong đó bệnh nhân không thể dễ dàng bị đánh thức nhưng có phản ứng có chủ đích sau khi kích thích lặp đi lặp lại hoặc gây đau. Khả năng duy trì chức năng hô hấp độc lập có thể bị suy giảm. Bệnh nhân có thể cần hỗ trợ để duy trì đường thở thông thoáng và thông khí tự nhiên có thể không đủ. Chức năng tim mạch thường được duy trì mà không cần các biện pháp hỗ trợ. Gây mê toàn thân: Gây mê toàn thân là tình trạng mất ý thức do thuốc gây ra, trong đó bệnh nhân không thể tỉnh lại, ngay cả khi bị kích thích đau. Khả năng duy trì chức năng hô hấp độc lập thường bị suy giảm. Bệnh nhân thường cần hỗ trợ để duy trì đường thở thông thoáng và có thể cần thở máy áp lực dương do suy giảm thông khí tự nhiên hoặc suy giảm chức năng thần kinh cơ do thuốc gây ra. Chức năng tim mạch có thể bị suy giảm. ( SC) Gây mê và chăm sóc phẫu thuật (ASC) Vì phẫu thuật có mức độ rủi ro cao, thông tin về quy trình phẫu thuật và chăm sóc sau phẫu thuật được lên kế hoạch cẩn thận, dựa trên đánh giá của bệnh nhân và được ghi chép lại. Phẫu thuật liên quan đến việc cấy ghép thiết bị y tế được cân nhắc đặc biệt, bao gồm báo cáo về các thiết bị bị trục trặc, cũng như quy trình theo dõi bệnh nhân trong trường hợp thu hồi. Lưu ý: Các tiêu chuẩn gây mê và phẫu thuật được áp dụng trong bất kỳ bối cảnh nào sử dụng gây mê và/hoặc an thần thủ thuật và nơi thực hiện phẫu thuật và các thủ thuật xâm lấn khác đòi hỏi phải có sự đồng ý. Các bối cảnh như vậy bao gồm phòng phẫu thuật của bệnh viện, khoa phẫu thuật trong ngày hoặc khoa bệnh viện trong ngày, nội soi, X quang can thiệp, phòng khám nha khoa và các phòng khám ngoại trú khác, dịch vụ cấp cứu, khu vực chăm sóc đặc biệt hoặc nơi khác. Tiêu chuẩn Sau đây là danh sách tất cả các tiêu chuẩn cho chức năng này. Chúng được trình bày ở đây để thuận tiện cho bạn mà không có các tuyên bố ý định hoặc các yếu tố có thể đo lường. Để biết thêm thông tin về các tiêu chuẩn này, vui lòng xem phần tiếp theo trong chương này, Tiêu chuẩn, Ý định và Các yếu tố có thể đo lường. Tổ chức và Quản lý ASC.01.00 Bệnh viện cung cấp dịch vụ gây mê và an thần để đáp ứng nhu cầu của bệnh nhân và theo đúng luật pháp và quy định. ASC.02.00 Việc thực hiện gây mê thủ thuật được chuẩn hóa trong toàn bệnh viện. ASC.02.01 Các bác sĩ chịu trách nhiệm về an thần trong quá trình phẫu thuật và nhân viên chịu trách nhiệm theo dõi bệnh nhân đang được an thần trong quá trình phẫu thuật đều có trình độ chuyên môn. ASC.02.02 Việc gây mê thủ thuật được thực hiện và theo dõi theo hướng dẫn thực hành chuyên môn và được ghi lại trong hồ sơ y tế của bệnh nhân. ASC.02.03 Các rủi ro, lợi ích và các phương án thay thế liên quan đến việc gây mê thủ thuật được thảo luận với bệnh nhân, gia đình của họ hoặc những người ra quyết định thay cho bệnh nhân. Chăm sóc gây mê ASC.03.00 Một cá nhân đủ tiêu chuẩn sẽ tiến hành đánh giá trước khi gây mê và đánh giá trước khi gây mê. ASC.03.01 Kế hoạch chăm sóc gây mê của mỗi bệnh nhân được thảo luận với bệnh nhân và/hoặc những người ra quyết định cho bệnh nhân và được ghi lại trong hồ sơ y tế của bệnh nhân. ASC.03.02 Tình trạng sinh lý của mỗi bệnh nhân trong quá trình gây mê và phẫu thuật được theo dõi theo hướng dẫn thực hành chuyên môn và được ghi lại trong hồ sơ y tế của bệnh nhân. ASC.03.03 Tình trạng sau gây mê của mỗi bệnh nhân được theo dõi và bệnh nhân được xuất viện khỏi khu vực hồi sức bởi một cá nhân có trình độ hoặc bằng cách sử dụng các tiêu chuẩn đã thiết lập. Chăm sóc sau phẫu thuật ASC.04.00 Việc chăm sóc phẫu thuật của mỗi bệnh nhân được lên kế hoạch dựa trên kết quả đánh giá trước phẫu thuật và được ghi lại trong hồ sơ y tế của bệnh nhân. ASC.04.01 Các rủi ro, lợi ích và các phương án thay thế được thảo luận với bệnh nhân và gia đình của họ hoặc những người ra quyết định thay cho bệnh nhân. ( SC) ASC.04.02 Thông tin về quy trình phẫu thuật được ghi lại trong hồ sơ y tế của bệnh nhân để tạo điều kiện cho việc chăm sóc liên tục. ASC.04.03 Việc chăm sóc bệnh nhân sau phẫu thuật được lên kế hoạch và ghi chép lại. ( SC) Gây mê và chăm sóc phẫu thuật (ASC) ASC.04.04 Surgical care that includes the implanting of a medical device is planned with special consideration for how standard processes must be modified. Tổ chức và Quản lý","b":[]}],"sec":"Dịch vụ Y học hạt nhân"},{"c":"APR.01.00","ch":"APR","t":"Bệnh viện gửi thông tin cho Ủy ban chung quốc tế (JCI) theo yêu cầu.","p":"","m":[],"sec":"Yêu cầu tham gia (APR)"},{"c":"APR.02.00","ch":"APR","t":"Bệnh viện cung cấp thông tin chính xác trong suốt quá trình công nhận.","p":"","m":[],"sec":"Yêu cầu tham gia (APR)"},{"c":"APR.03.00","ch":"APR","t":"Bệnh viện báo cáo bất kỳ thay đổi nào về thông tin được cung cấp trong đơn xin công nhận và bất kỳ thay đổi nào được thực hiện giữa các cuộc khảo sát.","p":"","m":[],"sec":"Yêu cầu tham gia (APR)"},{"c":"APR.04.00","ch":"APR","t":"Bệnh viện cho phép thực hiện khảo sát theo quyết định của JCI.","p":"","m":[],"sec":"Yêu cầu tham gia (APR)"},{"c":"APR.09.00","ch":"APR","t":"Bệnh viện thông báo cho công chúng về cách liên hệ với ban quản lý bệnh viện và JCI để báo cáo các mối quan ngại về an toàn bệnh nhân và chất lượng chăm sóc.","p":"","m":[],"sec":"Requirements (APR)"},{"c":"APR.10.00","ch":"APR","t":"Các dịch vụ biên dịch và phiên dịch do bệnh viện sắp xếp cho cuộc khảo sát công nhận và bất kỳ hoạt động liên quan nào đều được cung cấp bởi các chuyên gia biên dịch và phiên dịch có trình độ, không có mối quan hệ nào với bệnh viện.","p":"","m":[],"sec":"Requirements (APR)"},{"c":"ASC.01.00","ch":"ASC","t":"Bệnh viện cung cấp dịch vụ gây mê và an thần để đáp ứng nhu cầu của bệnh nhân và theo các tiêu chuẩn hành nghề và luật pháp, quy định.","p":"Với sự phức tạp liên quan đến việc chăm sóc gây mê và an thần, bệnh viện phải có một hệ thống tại chỗ để\ncung cấp các dịch vụ như vậy phản ánh nhóm bệnh nhân, các dịch vụ lâm sàng được cung cấp và nhu cầu của\ncác bác sĩ chăm sóc sức khỏe. Gây mê và an thần thường được coi là một quá trình liên tục từ gây mê tối thiểu\nđến gây mê toàn phần. Sử dụng gây mê và an thần là các quá trình phức tạp phải được tích hợp vào kế hoạch\nchăm sóc bệnh nhân bao gồm các giai đoạn gây mê và an thần. Gây mê và an thần đòi hỏi phải đánh giá bệnh\nnhân đầy đủ và toàn diện (gây mê trước/gây mê), theo dõi bệnh nhân liên tục (gây mê trong thủ thuật/gây mê\ntrong khi phẫu thuật) và các tiêu chí phục hồi khách quan (gây mê sau thủ thuật/gây mê sau phẫu thuật). Các\ndịch vụ này được cung cấp theo các tiêu chuẩn thực hành chuyên môn về chăm sóc, đáp ứng tất cả\nluật và quy định hiện hành của địa phương và quốc gia, và phải luôn sẵn sàng cho các trường hợp khẩn cấp.\nTheo khuyến nghị của Hiệp hội Điều dưỡng viên Đăng ký Phẫu thuật (AORN, 2022), bệnh viện\ncung cấp cùng một tiêu chuẩn chăm sóc (tức là theo dõi bệnh nhân và trang thiết bị) cho những bệnh nhân\nđang được gây mê/gây mê thủ thuật và gây mê tại các địa điểm gây mê không phải phòng phẫu thuật (ví dụ:\ntim mạch can thiệp, nội soi, nha khoa, X quang, phẫu thuật tại phòng khám) như đối với những bệnh nhân\nđang được gây mê/gây mê vừa phải và gây mê tại phòng phẫu thuật.\n\nDịch vụ gây mê và gây mê có thể được cung cấp bởi bệnh viện, theo thỏa thuận với một dịch vụ theo hợp\nđồng (ví dụ: một bác sĩ gây mê cá nhân hoặc nhóm thực hành gây mê), hoặc cả hai. Bất kỳ việc sử dụng dịch\nvụ gây mê theo hợp đồng nào đều dựa trên khuyến nghị của cá nhân đủ điều kiện chịu trách nhiệm quản lý\ndịch vụ gây mê và gây mê. Dịch vụ gây mê và gây mê được chỉ đạo bởi một hoặc nhiều cá nhân đủ điều kiện\nthông qua đào tạo, chuyên môn và kinh nghiệm được ghi chép, phù hợp với luật pháp và quy định hiện hành.\nCá nhân này đảm nhận trách nhiệm chuyên môn và một số trách nhiệm quản lý đối với các dịch vụ gây mê\nđược cung cấp.\n\n( SC)\n\nGây mê và chăm sóc\nphẫu thuật (ASC)","m":[{"t":"Bệnh viện cung cấp dịch vụ gây mê và an thần đáp ứng nhu cầu của bệnh nhân mà bệnh viện phục vụ.","b":[]},{"t":"Bệnh viện cung cấp dịch vụ gây mê và an thần tuân thủ theo luật pháp và quy định.","b":[]},{"t":"Bệnh viện cung cấp dịch vụ gây mê và an thần tuân thủ theo các tiêu chuẩn hành nghề để chăm sóc.","b":[]},{"t":"Một hoặc nhiều cá nhân đủ điều kiện đảm nhận trách nhiệm chuyên môn đối với các dịch vụ gây mê được cung cấp bất kể địa điểm nào tại bệnh viện. Trách nhiệm bao gồm:","b":["Phát triển, triển khai và duy trì các chính sách và quy trình","Giám sát hành chính","Duy trì bất kỳ chương trình cải tiến chất lượng cần thiết nào","Theo dõi và xem xét tất cả các dịch vụ gây mê và an thần"]},{"t":"Cá nhân đủ điều kiện này chịu trách nhiệm quản lý các dịch vụ gây mê và an thần, bao gồm đảm bảo những điều sau:","b":["Các dịch vụ gây mê và an thần được thống nhất trong toàn bệnh viện.","Các dịch vụ gây mê và an thần luôn sẵn sàng phục vụ trong các trường hợp khẩn cấp.","Trách nhiệm theo dõi và xem xét tất cả các dịch vụ gây mê và an thần được xác định và thực hiện."]},{"t":"D Bệnh viện có quy trình lựa chọn dịch vụ gây mê theo hợp đồng bao gồm những điều sau:","b":["Phải sử dụng danh sách dịch vụ gây mê theo hợp đồng đã cập nhật để lựa chọn dịch vụ gây mê theo hợp đồng được lãnh đạo bệnh viện và cá nhân đủ điều kiện chịu trách nhiệm chuyên môn về dịch vụ gây mê chấp thuận.","Dịch vụ gây mê theo hợp đồng phải có hồ sơ thực hiện được chấp nhận và tuân thủ các luật và quy định hiện hành.","Bệnh viện phải có hồ sơ về tất cả các khóa đào tạo và giáo dục đã hoàn thành cho mỗi nhân viên gây mê theo hợp đồng theo yêu cầu của bệnh viện.","Phải có hợp đồng hiện hành khi sử dụng dịch vụ gây mê theo hợp đồng. (Xem thêm GLD.05.00, ME 3) Chăm sóc an thần"]}],"sec":"Tổ chức và Quản lý"},{"c":"ASC.02.00","ch":"ASC","t":"Việc thực hiện gây mê thủ thuật được chuẩn hóa trong toàn bệnh viện.","p":"Gây mê thủ thuật thường được thực hiện ở nhiều khu vực của bệnh viện bên ngoài phòng phẫu thuật.\nCác hướng dẫn thực hành lâm sàng và chuẩn hóa các hoạt động đã chứng minh được sự cải thiện về kết quả;\ncụ thể là các quy trình bao gồm các giao thức và danh sách kiểm tra, đã được chứng minh là làm giảm tác hại đối với\nbệnh nhân thông qua chuẩn hóa và giao tiếp. Do đó, các quy trình chuẩn hóa tối ưu hóa các hoạt động gây mê thủ\nthuật vừa phải bất kể địa điểm thực hiện dịch vụ; hướng dẫn lựa chọn bệnh nhân phù hợp; giảm nguy cơ gây ra các\nkết quả bất lợi cho bệnh nhân (ví dụ, ngưng thở, tắc nghẽn đường thở, ngừng thở, ngừng tim, tử vong); thúc đẩy\ngiáo dục, đào tạo và nghiên cứu về gây mê; và khuyến khích sử dụng dữ liệu dựa trên bằng chứng để thúc đẩy tính\nthống nhất giữa các chuyên khoa đối với các hoạt động gây mê vừa phải.\n\nGây mê thủ thuật được định nghĩa là “kỹ thuật dùng thuốc an thần hoặc thuốc gây phân ly có hoặc không có thuốc\ngiảm đau cho một cá nhân, trong bất kỳ bối cảnh nào, theo bất kỳ con đường nào, để tạo ra trạng thái ý thức thay đổi\ncho phép bệnh nhân chịu đựng các thủ thuật gây đau đớn hoặc khó chịu trong khi vẫn bảo tồn chức năng tim mạch\nhô hấp”.\n\n( SC)\n\nGây mê và chăm sóc\nphẫu thuật (ASC)\nBất kể loại thuốc, liều lượng hoặc đường dùng, khi thuốc được sử dụng nhằm mục đích thay đổi trạng thái nhận\nthức của bệnh nhân để tạo điều kiện thuận lợi cho một thủ thuật cụ thể, thì thuốc đó được coi là thuốc an thần trong\nthủ thuật.\n\nBệnh viện xây dựng các hướng dẫn cụ thể về cách thức và địa điểm có thể sử dụng thuốc an thần trong thủ thuật.\nTrình độ của nhân viên tham gia thủ thuật, thiết bị y tế, vật tư và việc theo dõi phải giống nhau ở bất kỳ nơi nào có\ncung cấp thuốc an thần trong thủ thuật tại bệnh viện. Một số loại thuốc nhất định có thể được sử dụng kết hợp với\nmột số nhóm dân số nhất định (ví dụ như nitơ oxit được sử dụng kết hợp với các thuốc giảm đau khác cho bệnh nhi\ntrong quá trình an thần vừa và sâu). Đối với những bệnh nhân được chăm sóc để an thần trong thủ thuật, những cá\nnhân từ cả điều dưỡng và nhân viên y tế được đào tạo về hỗ trợ sự sống nâng cao và thiết bị và vật tư y tế khẩn cấp\nphù hợp với độ tuổi và tiền sử của bệnh nhân và loại thủ thuật đang được thực hiện đều có sẵn ngay lập tức.","m":[{"t":"Bệnh viện đã thiết lập chính sách bằng văn bản và các quy trình chuẩn hóa cho việc gây mê thủ thuật trong toàn bệnh viện.","b":[]},{"t":"Chính sách và thực hành về an thần trong thủ thuật được tất cả các bác sĩ được phép thực hiện an thần trong thủ thuật hiểu rõ và các chính sách này đề cập đến ít nhất những điều sau đây:","b":["Các khu vực trong bệnh viện có thể xảy ra gây mê thủ thuật","Trình độ chuyên môn hoặc kỹ năng đặc biệt của nhân viên tham gia vào quá trình gây mê thủ thuật","Sự khác biệt giữa nhóm trẻ em, người lớn và người già hoặc các cân nhắc đặc biệt khác","Thuốc được sử dụng kết hợp với một số nhóm người nhất định","Có sẵn và sử dụng ngay thiết bị y tế chuyên dụng, tùy theo bệnh nhân","Quy trình đồng ý có thông tin đầy đủ cho cả thủ thuật và việc sử dụng thuốc an thần","Một cá nhân được đào tạo nâng cao về hỗ trợ sự sống sẽ có mặt ngay lập tức cho những bệnh nhân đang được chăm sóc để gây mê hoặc an thần trong thủ thuật. (Xem thêm SQE.01.08, ME 2)"]}],"sec":"Sedation Care"},{"c":"ASC.02.01","ch":"ASC","t":"Các bác sĩ chịu trách nhiệm về an thần trong quá trình phẫu thuật và nhân viên chịu trách nhiệm theo dõi bệnh nhân đang được an thần trong quá trình phẫu thuật đều có trình độ chuyên môn.","p":"Các biến chứng liên quan đến an thần trong thủ thuật chủ yếu bao gồm suy tim hoặc suy hô hấp. Do đó, chứng\nchỉ ít nhất là hỗ trợ sự sống cơ bản là điều cần thiết. Ngoài ra, kiến thức về dược lý của các tác nhân an thần\nđược sử dụng, cũng như các tác nhân đảo ngược, làm giảm nguy cơ xảy ra các kết quả bất lợi. Trình độ của bác\nsĩ, nha sĩ hoặc các nhân viên khác chịu trách nhiệm về việc bệnh nhân được an thần trong thủ thuật là rất quan\ntrọng. Hiểu các phương pháp an thần trong thủ thuật liên quan đến bệnh nhân và loại thủ thuật được thực hiện\nsẽ cải thiện khả năng chịu đựng của bệnh nhân đối với một thủ thuật khó chịu hoặc đau đớn và làm giảm nguy\ncơ biến chứng.\n\nBác sĩ chăm sóc sức khỏe thực hiện thủ thuật không nên chịu trách nhiệm theo dõi liên tục bệnh nhân. Một cá\nnhân riêng biệt, có trình độ, chẳng hạn như bác sĩ gây mê hoặc y tá được đào tạo và có năng lực, nên chịu trách\nnhiệm theo dõi liên tục các thông số sinh lý của bệnh nhân và hỗ trợ các biện pháp hỗ trợ hoặc hồi sức.\n\n( SC)\n\nGây mê và chăm sóc\nphẫu thuật (ASC)","m":[{"t":"Các bác sĩ chịu trách nhiệm cung cấp thuốc an thần trong thủ thuật phải chứng minh được năng lực trong ít nhất các nội dung sau:","b":["Các kỹ thuật và phương thức an thần khác nhau","Dược lý của thuốc an thần và việc sử dụng thuốc giải độc","Các yêu cầu theo dõi","Phản ứng với các biến chứng","Đánh giá đường thở (Xem thêm SQE.01.03, ME 1)"]},{"t":"Cá nhân chịu trách nhiệm theo dõi bệnh nhân trong quá trình an thần trong thủ thuật phải có năng lực trong ít nhất các nội dung sau:","b":["Các yêu cầu theo dõi từ giai đoạn dùng thuốc tích cực trong quá trình thực hiện thủ thuật cho đến giai đoạn phục hồi sau thủ thuật","Phản ứng với các biến chứng","Sử dụng thuốc giải độc","Tiêu chí phục hồi","Đánh giá đường thở (Xem thêm SQE.01.03, ME 1)"]},{"t":"Năng lực an thần trong thủ thuật của tất cả nhân viên tham gia vào quá trình an thần đều được ghi lại trong hồ sơ nhân sự.","b":[]}],"sec":"Sedation Care"},{"c":"ASC.02.02","ch":"ASC","t":"Việc gây mê thủ thuật được thực hiện và theo dõi theo hướng dẫn thực hành chuyên môn và được ghi lại trong hồ sơ y tế của bệnh nhân.","p":"Nhiều yếu tố ảnh hưởng đến phản ứng của bệnh nhân đối với thuốc an thần và có thể ảnh hưởng đến mức độ\nbệnh nhân được an thần. Đánh giá trước khi an thần giúp xác định bất kỳ yếu tố nào có thể ảnh hưởng đến\nphản ứng của bệnh nhân đối với thuốc an thần trong quá trình phẫu thuật và cũng giúp xác định những phát\nhiện nào từ quá trình theo dõi trong và sau quá trình phẫu thuật có thể có ý nghĩa. Các mức độ an thần diễn ra\nliên tục từ an thần nhẹ đến an thần sâu và bệnh nhân có thể tiến triển từ mức độ này sang mức độ khác. Các\nyếu tố bao gồm thuốc được dùng, đường dùng và liều dùng, độ tuổi của bệnh nhân (trẻ em, người lớn hoặc\nngười già) và tiền sử sức khỏe của bệnh nhân. Ví dụ,\ntiền sử suy giảm chức năng các cơ quan chính, thuốc hiện tại có thể tương tác với thuốc an thần, dị ứng thuốc,\nphản ứng có hại trước đó với thuốc gây mê hoặc thuốc an thần và lạm dụng chất gây nghiện đều có thể ảnh\nhưởng đến\nphản ứng của bệnh nhân đối với thuốc an thần trong quá trình phẫu thuật. Nếu tình trạng thể chất của bệnh\nnhân có nguy cơ cao, chúng tôi sẽ cân nhắc\ncác nhu cầu lâm sàng bổ sung của bệnh nhân và tính phù hợp của thuốc an thần trong quá trình phẫu thuật. Các\nyếu tố này được\nbao gồm trong đánh giá tiền mê do một cá nhân đủ điều kiện thực hiện và được ghi lại trong\nhồ sơ y tế của bệnh nhân.\n\nBệnh nhân trải qua quá trình an thần cần được theo dõi mức độ ý thức, tình trạng thở máy và oxy hóa, và các\nbiến số huyết động ở tần suất dựa trên loại và lượng thuốc được dùng, thời gian của quá trình và loại và tình\ntrạng của bệnh nhân. Những cân nhắc quan trọng trong quá trình an thần bao gồm khả năng duy trì phản xạ bảo\nvệ của bệnh nhân; đường thở thông thoáng độc lập, liên tục; và khả năng phản ứng với kích thích vật lý hoặc\nlệnh bằng lời nói. Một cá nhân có trình độ chuyên môn có trách nhiệm theo dõi liên tục các thông số sinh lý\ncủa bệnh nhân và hỗ trợ các biện pháp hỗ trợ hoặc hồi sức cho đến khi bệnh nhân hồi phục an toàn.\n\n( SC)\n\nKhi thủ thuật đã hoàn tất, bệnh nhân có thể tiếp tục có nguy cơ gặp biến chứng do chậm hấp thu hoàn toàn thuốc\nan thần, suy hô hấp và/hoặc thiếu kích thích từ thủ thuật. Bệnh nhân tiếp tục cần được theo dõi cho đến khi đạt\ngần mức ý thức và các thông số huyết động cơ bản. Các biến chứng liên quan đến an thần và giảm đau vừa phải có\nthể tránh được nếu các dấu hiệu và triệu chứng của tác dụng phụ của thuốc như mất bù tim mạch hoặc thiếu oxy\nnão được phát hiện và điều trị kịp thời. Theo dõi bệnh nhân bao gồm các chiến lược sau:\n•\nTheo dõi mức độ ý thức của bệnh nhân được đánh giá bằng phản ứng của bệnh nhân trong các thủ thuật được\nthực hiện với thuốc an thần/giảm đau vừa phải.\n•\nTheo dõi thông khí và oxy hóa của bệnh nhân, bao gồm chức năng thông khí, bằng cách quan sát các dấu hiệu\nlâm sàng định tính, đo nồng độ carbon dioxide trong máu và đo độ bão hòa oxy trong máu.\n•\nTheo dõi huyết động, bao gồm huyết áp, nhịp tim và điện tâm đồ\n•\nGhi lại đồng thời các thông số được theo dõi\n•\nSự sẵn có/có mặt của một cá nhân chịu trách nhiệm theo dõi bệnh nhân\nNgoài việc theo dõi các tiêu chí sinh lý, các chiến lược quan trọng khác cần đưa vào là tần suất theo dõi và ghi chép, hướng\ndẫn chung và/hoặc các thông số cho mục tiêu phục hồi. Các tiêu chí được thiết lập khách quan giúp xác định những bệnh\nnhân đã hồi phục và/hoặc sẵn sàng xuất viện và được sử dụng bởi những cá nhân đủ điều kiện không phải là bác sĩ gây\nmê đủ điều kiện nhưng được cá nhân(các cá nhân) chịu trách nhiệm quản lý các dịch vụ gây mê cho phép.","m":[{"t":"Đánh giá trước khi gây mê được thực hiện bao gồm ít nhất các tiêu chí sau khi đánh giá rủi ro và tính phù hợp của việc gây mê thủ thuật đối với bệnh nhân:","b":["Xác định các vấn đề về đường thở có thể ảnh hưởng đến loại gây mê được sử dụng.","Đánh giá những bệnh nhân có nguy cơ về tính phù hợp của việc gây mê thủ thuật.","Lựa chọn và lập kế hoạch loại và mức độ gây mê cần thiết dựa trên đánh giá của bệnh nhân, các rủi ro đã xác định và loại thủ thuật đang được thực hiện.","Thực hiện gây mê an toàn dựa trên kế hoạch.","Giải thích các phát hiện từ quá trình theo dõi bệnh nhân trong quá trình gây mê thủ thuật và hồi phục."]},{"t":"Một cá nhân đủ điều kiện sẽ theo dõi bệnh nhân trong suốt thời gian gây mê và ghi lại việc theo dõi trong hồ sơ y tế.","b":[]},{"t":"Các tiêu chí đã thiết lập được sử dụng và ghi lại để hồi phục và xuất viện sau khi gây mê thủ thuật khi bệnh nhân được một cá nhân có thẩm quyền khác ngoài bác sĩ gây mê đủ điều kiện xuất viện.","b":[]},{"t":"Đánh giá tiền mê được thực hiện bởi một hoặc nhiều cá nhân đủ điều kiện để làm như vậy và được ghi lại trong hồ sơ y tế của bệnh nhân.","b":[]},{"t":"Các tiêu chí sau đây dựa trên các hướng dẫn thực hành chuyên môn và được xác định trong chính sách của bệnh viện:","b":["Phạm vi và nội dung của đánh giá tiền mê","Tiêu chí phục hồi và xuất viện sau khi gây mê thủ thuật, bao gồm các tiêu chí theo dõi"]}],"sec":"Sedation Care"},{"c":"ASC.02.03","ch":"ASC","t":"Các rủi ro, lợi ích và các phương án thay thế liên quan đến việc gây mê thủ thuật được thảo luận với bệnh nhân, gia đình của họ hoặc những người ra quyết định thay cho bệnh nhân.","p":"Cần cung cấp thông tin và giáo dục đầy đủ cho bệnh nhân, gia đình và/hoặc những người ra quyết định về các rủi ro,\nlợi ích và các phương án thay thế liên quan đến gây mê thủ thuật để có thể đưa ra quyết định sáng suốt khi xin sự đồng\ný cho thủ thuật. Quy trình lập kế hoạch gây mê thủ thuật bao gồm thông tin và giáo dục này. Thảo luận này diễn ra\nnhư một phần của quy trình xin sự đồng ý cho gây mê thủ thuật theo yêu cầu trong","m":[],"sec":"Sedation Care"},{"c":"ASC.03.00","ch":"ASC","t":"Một cá nhân đủ tiêu chuẩn sẽ tiến hành đánh giá trước khi gây mê và đánh giá trước khi gây mê.","p":"Vì gây mê có mức độ rủi ro cao như vậy nên việc thực hiện phải được lên kế hoạch cẩn thận. Do đó, bác sĩ\ngây mê hoặc một cá nhân đủ tiêu chuẩn khác sẽ tiến hành đánh giá tiền gây mê. Đánh giá tiền gây mê của bệnh\nnhân là cơ sở cho kế hoạch chăm sóc gây mê, bao gồm xác định những phát hiện nào từ đánh giá lâm sàng và\ntừ việc theo dõi trong quá trình gây mê và hồi phục có thể có ý nghĩa, và để sử dụng thuốc giảm đau sau phẫu\nthuật. Đánh giá tiền gây mê có thể được thực hiện một thời gian trước khi nhập viện hoặc trước khi tiến\nhành phẫu thuật hoặc ngay trước khi tiến hành phẫu thuật, như đối với bệnh nhân cấp cứu và sản khoa.\n\nĐánh giá tiền gây mê tách biệt với đánh giá tiền gây mê, vì đánh giá này tập trung vào sự ổn định về mặt sinh\nlý và sự sẵn sàng của bệnh nhân để gây mê và diễn ra ngay trước khi gây mê. Khi phải gây mê khẩn cấp, đánh\ngiá tiền gây mê và đánh giá tiền gây mê có thể được thực hiện ngay sau nhau hoặc đồng thời, nhưng được ghi\nchép lại một cách độc lập.","m":[{"t":"Đánh giá trước khi gây mê được thực hiện bao gồm ít nhất các yếu tố sau khi đánh giá rủi ro và tính phù hợp của việc gây mê cho bệnh nhân:","b":["Xác định các vấn đề về đường thở có thể ảnh hưởng đến loại gây mê được sử dụng.","Đánh giá bệnh nhân có nguy cơ để gây mê phù hợp.","Chọn phương pháp gây mê và lên kế hoạch gây mê.","Thực hiện gây mê an toàn dựa trên đánh giá của bệnh nhân, các rủi ro đã xác định và loại thủ thuật.","Diễn giải các phát hiện từ quá trình theo dõi bệnh nhân trong quá trình gây mê và hồi phục.","Cung cấp thông tin về việc sử dụng thuốc giảm đau sau phẫu thuật."]},{"t":"Đánh giá trước khi gây mê riêng biệt được thực hiện để đánh giá lại bệnh nhân ngay trước khi gây mê.","b":[]},{"t":"Đánh giá trước khi gây mê và đánh giá trước khi gây mê được thực hiện bởi cá nhân có đủ trình độ và được ghi vào hồ sơ y tế của bệnh nhân.","b":[]},{"t":"Phạm vi và nội dung của đánh giá trước gây mê và đánh giá trước khi gây mê dựa trên các hướng dẫn chuyên môn và được xác định trong chính sách của bệnh viện.","b":[]}],"sec":"Chăm sóc gây mê"},{"c":"ASC.03.01","ch":"ASC","t":"Kế hoạch chăm sóc gây mê của mỗi bệnh nhân được thảo luận với bệnh nhân và/hoặc những người ra quyết định cho bệnh nhân và được ghi lại trong hồ sơ y tế của bệnh nhân.","p":"Quy trình lập kế hoạch gây mê bao gồm việc giáo dục bệnh nhân, gia đình và/hoặc người ra quyết định về các rủi ro,\nlợi ích và các phương án thay thế liên quan đến việc gây mê theo kế hoạch. Cuộc thảo luận này diễn ra như một\nphần của quy trình để có được sự đồng ý gây mê theo yêu cầu trong","m":[],"sec":"Chăm sóc gây mê"},{"c":"ASC.03.02","ch":"ASC","t":"Tình trạng sinh lý của mỗi bệnh nhân trong quá trình gây mê và phẫu thuật được theo dõi theo hướng dẫn thực hành chuyên môn và được ghi lại trong hồ sơ y tế của bệnh nhân.","p":"Theo dõi sinh lý cung cấp thông tin đáng tin cậy về tình trạng của bệnh nhân trong quá trình gây mê (toàn\nthân, tủy sống và khu vực) và thời gian phục hồi. Thông tin theo dõi hướng dẫn chăm sóc y tế và điều dưỡng\nvà xác định nhu cầu về chẩn đoán và các dịch vụ khác. Kết quả theo dõi kích hoạt các quyết định quan trọng\ntrong khi phẫu thuật cũng như các quyết định sau phẫu thuật, chẳng hạn như quay lại phẫu thuật, chuyển\nsang cấp độ chăm sóc khác hoặc xuất viện.\nCác phát hiện theo dõi được nhập vào hồ sơ y tế của bệnh nhân. Các phương pháp theo dõi phụ thuộc\nvào tình trạng tiền gây mê của bệnh nhân, lựa chọn gây mê và mức độ phức tạp của phẫu thuật hoặc các thủ\nthuật khác được thực hiện trong quá trình gây mê. Tuy nhiên, trong mọi trường hợp, việc theo dõi tổng thể\ntrong quá trình gây mê và phẫu thuật đều phù hợp với thông lệ chuyên môn và được xác định trong chính\nsách của bệnh viện. Kết quả theo dõi được ghi lại trong hồ sơ y tế của bệnh nhân.","m":[{"t":"Tần suất và loại theo dõi trong quá trình gây mê và phẫu thuật dựa trên tình trạng tiền gây mê của bệnh nhân, thuốc gây mê được sử dụng và quy trình phẫu thuật được thực hiện.","b":[]},{"t":"Việc theo dõi tình trạng sinh lý của bệnh nhân phải phù hợp với các hướng dẫn thực hành chuyên môn.","b":[]},{"t":"Kết quả theo dõi được ghi lại trong hồ sơ y tế của bệnh nhân. (Xem thêm COP.01.00, ME 5) ( SC) Gây mê và chăm sóc phẫu thuật (ASC)","b":[]}],"sec":"Chăm sóc gây mê"},{"c":"ASC.03.03","ch":"ASC","t":"Tình trạng sau gây mê của mỗi bệnh nhân được theo dõi và bệnh nhân được xuất viện khỏi khu vực hồi sức bởi một cá nhân có trình độ hoặc bằng cách sử dụng các tiêu chuẩn đã thiết lập.","p":"Việc thu thập và phân tích dữ liệu liên tục, có hệ thống về tình trạng bệnh nhân trong quá trình phục hồi hỗ trợ các\nquyết định chuyển bệnh nhân đến các cơ sở khác và các dịch vụ ít chuyên sâu hơn. Theo dõi trong thời gian gây mê là\ncơ sở để theo dõi trong thời gian phục hồi sau gây mê. Theo dõi bao gồm một số yếu tố, chẳng hạn như danh sách các\ntiêu chí sinh lý cần theo dõi, tần suất theo dõi và ghi chép, hướng dẫn chung và/hoặc các thông số cho mục tiêu phục\nhồi. Theo dõi trong thời gian phục hồi sau gây mê phải được thực hiện theo hướng dẫn thực hành chuyên môn và theo\nquy định trong chính sách của bệnh viện. Ghi lại dữ liệu theo dõi cung cấp tài liệu để hỗ trợ việc ngừng theo dõi phục\nhồi hoặc quyết định xuất viện. Khi bệnh nhân được chuyển trực tiếp từ phòng phẫu thuật đến đơn vị tiếp nhận, việc\ntheo dõi và ghi chép giống như yêu cầu trong phòng hồi sức.\n\nThời gian đến và xuất viện khỏi khu vực hồi sức (hoặc thời gian bắt đầu phục hồi và thời gian ngừng theo dõi phục\nhồi) và các phát hiện theo dõi trong thời gian phục hồi sau gây mê được ghi lại trong hồ sơ y tế của bệnh nhân.","m":[{"t":"Bệnh nhân được theo dõi trong thời gian phục hồi sau gây mê theo hướng dẫn thực hành chuyên môn và theo quy định trong chính sách của bệnh viện.","b":[]},{"t":"Các phát hiện theo dõi được ghi lại trong hồ sơ y tế của bệnh nhân.","b":[]},{"t":"Bệnh nhân được xuất viện khỏi đơn vị gây mê sau gây mê hoặc việc theo dõi phục hồi bị ngừng theo một trong các phương án thay thế sau:","b":["Bệnh nhân được xuất viện hoặc việc theo dõi phục hồi bị ngừng lại, bởi một bác sĩ gây mê có trình độ đầy đủhoặc cá nhân khác được cá nhân(các cá nhân) chịu trách nhiệm quản lý dịch vụ gây mê ủy quyền.","Bệnh nhân được xuất viện hoặc việc theo dõi phục hồi bị ngừng lại, bởi một y tá hoặc cá nhân có trình độ tương tự theo tiêu chuẩn gây tê xương do các nhà lãnh đạo bệnh viện xây dựng và hồ sơ y tế của bệnh nhân có bằng chứng đáp ứng các tiêu chuẩn.","Bệnh nhân được xuất viện đến một đơn vị có khả năng cung cấp dịch vụ chăm sóc sau gây mê hoặc sau gây mê cho những bệnh nhân được lựa chọn, chẳng hạn như đơn vị chăm sóc tích cực tim mạch hoặc đơn vị chăm sóc tích cực phẫu thuật thần kinh, trong số những đơn vị khác."]},{"t":"Thời gian hồi phục sau gây mê được ghi lại trong hồ sơ y tế của bệnh nhân:","b":["Thời gian phục hồi bắt đầu","Giai đoạn phục hồi thời gian đã hoàn tất Chăm sóc phẫu thuật"]}],"sec":"Chăm sóc gây mê"},{"c":"ASC.04.00","ch":"ASC","t":"Việc chăm sóc phẫu thuật của mỗi bệnh nhân được lên kế hoạch dựa trên kết quả đánh giá trước phẫu thuật và được ghi lại trong hồ sơ y tế của bệnh nhân.","p":"Đánh giá trước phẫu thuật là đánh giá rủi ro lâm sàng để xác định xem bệnh nhân có thể phẫu thuật an toàn hay không; do đó,\nđây là yếu tố quyết định quan trọng để tiến hành lập kế hoạch phẫu thuật.\n\n( SC)\n\nGây mê và chăm sóc\nphẫu thuật (ASC)\nNgoài ra, đánh giá được sử dụng để lựa chọn quy trình phẫu thuật phù hợp và xác định nhu cầu của bệnh nhân liên\nquan đến phẫu thuật.\nĐánh giá trước phẫu thuật đánh giá tình trạng và nhu cầu của bệnh nhân trước khi phẫu thuật. Đánh giá bao gồm\nnhững nội dung sau:\n•\nKết quả kiểm tra và khám sức khỏe\n•\nNhu cầu y tế\n•\nNhu cầu tâm lý\n•\nNhu cầu xã hội (ví dụ, nhà ở an toàn và hỗ trợ các hoạt động sinh hoạt hàng ngày)\n•\nNhu cầu kinh tế (ví dụ, khả năng chi trả cho thuốc men hoặc thiết bị y tế sau phẫu thuật)\n•\nNhu cầu xuất viện (ví dụ, chuyển đến trung tâm phục hồi chức năng hoặc nhu cầu chăm sóc tại nhà)\nKết quả đánh giá trước phẫu thuật được ghi lại trong hồ sơ y tế của bệnh nhân trước khi phẫu thuật. Đánh giá cung\ncấp thông tin cần thiết để thực hiện các việc sau:\n•\nChọn thủ thuật phẫu thuật phù hợp và thời điểm tối ưu để thực hiện phẫu thuật.\n•\nThực hiện thủ thuật một cách an toàn.\n•\nDiễn giải các phát hiện trong quá trình theo dõi bệnh nhân trong khi phẫu thuật.\nViệc lựa chọn thủ thuật phẫu thuật phụ thuộc vào các yếu tố sau:\n•\nTiền sử bệnh nhân\n•\nTình trạng thể chất\n•\nDữ liệu chẩn đoán\n•\nRủi ro và lợi ích của thủ thuật đối với bệnh nhân\nViệc lựa chọn thủ thuật xem xét thông tin từ các đánh giá và đánh giá lại ban đầu, các xét nghiệm chẩn đoán và các\nnguồn thông tin có sẵn khác. Quá trình đánh giá được thực hiện trong một khung thời gian ngắn hơn khi bệnh\nnhân cấp cứu cần phẫu thuật.\nViệc chăm sóc phẫu thuật theo kế hoạch được ghi lại trong hồ sơ y tế của bệnh nhân và bao gồm chẩn đoán\ntrước phẫu thuật. Tên của quy trình phẫu thuật không cấu thành chẩn đoán.","m":[{"t":"Đánh giá trước phẫu thuật được thực hiện và ghi chép bởi một nhà cung cấp đủ điều kiện trước khi phẫu thuật.","b":[]},{"t":"Đánh giá trước phẫu thuật bao gồm những nội dung sau:","b":["Kết quả khám sức khỏe và xét nghiệm","Nhu cầu y tế","Nhu cầu tâm lý","Nhu cầu xã hội","Nhu cầu kinh tế","Nhu cầu xuất viện"]},{"t":"Chăm sóc phẫu thuật cho mỗi bệnh nhân được lập kế hoạch dựa trên thông tin đánh giá trước phẫu thuật.","b":[]},{"t":"Chẩn đoán trước phẫu thuật và quy trình phẫu thuật đã lên kế hoạch được ghi chép trong hồ sơ y tế của bệnh nhân trước khi thực hiện quy trình. Tiêu chuẩn ASC.4.01 Các rủi ro, lợi ích và các phương án thay thế được thảo luận với bệnh nhân và gia đình của họ hoặc những người ra quyết định thay cho bệnh nhân. Mục đích của ASC.04.01 Cần cung cấp thông tin và giáo dục đầy đủ cho bệnh nhân, gia đình và/hoặc những người ra quyết định về các rủi ro, lợi ích và các phương án thay thế liên quan đến chăm sóc phẫu thuật để tham gia vào các quyết định chăm sóc và cung cấp sự đồng ý có thông tin theo yêu cầu trong","b":[]}],"sec":"Chăm sóc sau phẫu thuật"},{"c":"ASC.04.01","ch":"ASC","t":"Các rủi ro, lợi ích và các phương án thay thế được thảo luận với bệnh nhân và gia đình của họ hoặc những người ra quyết định thay cho bệnh nhân.","p":"","m":[],"sec":"Chăm sóc sau phẫu thuật"},{"c":"ASC.04.02","ch":"ASC","t":"Thông tin về quy trình phẫu thuật được ghi lại trong hồ sơ y tế của bệnh nhân để tạo điều kiện cho việc chăm sóc liên tục.","p":"Chăm sóc hậu phẫu của bệnh nhân phụ thuộc vào các sự kiện và phát hiện của quy trình phẫu thuật. Quan trọng\nnhất, tất cả các hành động và kết quả cần thiết cho tình trạng của bệnh nhân đều được nhập vào hồ sơ y tế\ncủa bệnh nhân. Thông tin bệnh nhân có thể được trình bày ở nhiều định dạng khác nhau, chẳng hạn như mẫu\n(giấy hoặc điện tử), báo cáo phẫu thuật như ghi chú tiến trình phẫu thuật bằng văn bản hoặc ghi chú về dịch vụ\nđiều trị hoặc chăm sóc khác. Để hỗ trợ quá trình chăm sóc hỗ trợ hậu phẫu liên tục, thông tin về ca phẫu thuật\nđược ghi vào hồ sơ y tế của bệnh nhân ngay sau khi phẫu thuật, trước khi bệnh nhân được chuyển khỏi khu\nvực phẫu thuật hoặc khu vực hồi phục sau gây mê. Thời gian ngay sau phẫu thuật được định nghĩa là \"sau khi\nhoàn thành ca phẫu thuật, trước khi bệnh nhân được chuyển đến cấp độ chăm sóc tiếp theo\".\n\nThông tin cũng có thể được chứa trong các ghi chú khác trong hồ sơ y tế. Ví dụ, lượng máu mất và lượng\nmáu truyền có thể được ghi lại trong hồ sơ gây mê hoặc thông tin về các thiết bị cấy ghép có thể được hiển thị\nbằng nhãn dán in sẵn của nhà sản xuất. Xác định thời gian ngay sau khi phẫu thuật (ví dụ, \"sau khi hoàn thành\nphẫu thuật, trước khi bệnh nhân được chuyển đến cấp độ chăm sóc tiếp theo\") đảm bảo thông tin liên quan có\nsẵn cho người chăm sóc tiếp theo. Nếu bác sĩ phẫu thuật đi cùng bệnh nhân từ phòng phẫu thuật đến đơn vị\nhoặc khu vực chăm sóc tiếp theo, ghi chú phẫu thuật, mẫu hoặc ghi chú tiến trình có thể được viết trong đơn vị\nhoặc khu vực chăm sóc đó.\nLưu ý: Tài liệu thông tin về các thủ thuật và phương pháp điều trị không phẫu thuật, chẳng hạn như các thủ\nthuật chẩn đoán xâm lấn, phương pháp điều trị can thiệp và các chẩn đoán và phương pháp điều trị khác, được\nxác định trong COP.01.01.","m":[{"t":"Báo cáo phẫu thuật, mẫu hoặc ghi chú tiến trình phẫu thuật bao gồm ít nhất các yếu tố sau:","b":["Chẩn đoán trước phẫu thuật và quy trình đã lên kế hoạch","Chẩn đoán sau phẫu thuật","Tên bác sĩ phẫu thuật và trợ lý ( SC) Gây mê và chăm sóc phẫu thuật (ASC)","Các quy trình đã thực hiện và mô tả các phát hiện của từng quy trình","Biến chứng quanh phẫu thuật","Đặt ống và/hoặc dẫn lưu trong khi phẫu thuật","Gửi mẫu phẫu thuật để xét nghiệm","Lượng máu mất và lượng máu truyền","Ngày, giờ và chữ ký của bác sĩ chịu trách nhiệm"]},{"t":"Bệnh viện xác định thông tin có thể được ghi lại thường xuyên trong các khu vực cụ thể khác của hồ sơ y tế.","b":[]},{"t":"Báo cáo phẫu thuật, mẫu hoặc ghi chú tiến trình phẫu thuật có sẵn ngay sau khi phẫu thuật trước khi bệnh nhân được chuyển đến cấp độ chăm sóc tiếp theo.","b":[]}],"sec":"Chăm sóc sau phẫu thuật"},{"c":"ASC.04.03","ch":"ASC","t":"Việc chăm sóc bệnh nhân sau phẫu thuật được lên kế hoạch và ghi chép lại.","p":"Nhu cầu chăm sóc y tế và điều dưỡng sau phẫu thuật của mỗi bệnh nhân khác nhau tùy thuộc vào quy trình phẫu\nthuật được thực hiện và tiền sử sức khỏe của bệnh nhân. Việc lập kế hoạch chăm sóc sau phẫu thuật có thể bắt\nđầu trước khi phẫu thuật dựa trên nhu cầu và tình trạng được đánh giá của bệnh nhân và loại phẫu thuật được\nthực hiện. Một số bệnh nhân có thể cần được chăm sóc từ các dịch vụ khác, chẳng hạn như vật lý trị liệu hoặc\nphục hồi chức năng; do đó, cần phải lập kế hoạch cho việc chăm sóc đó, bao gồm mức độ chăm sóc, bối cảnh chăm\nsóc, theo dõi hoặc điều trị theo dõi và nhu cầu về\nthuốc hoặc các phương pháp điều trị và dịch vụ khác. Kế hoạch chăm sóc sau phẫu thuật cũng bao gồm các nhu\ncầu hậu phẫu ngay lập tức của bệnh nhân.\n\nViệc chăm sóc sau phẫu thuật được lập kế hoạch, ghi vào hồ sơ y tế của bệnh nhân trong vòng 24 giờ và được\ndịch vụ có trách nhiệm xác minh để đảm bảo tính liên tục của các dịch vụ trong thời gian phục hồi hoặc phục hồi\nchức năng. Nhu cầu sau phẫu thuật có thể thay đổi do cải thiện lâm sàng hoặc thông tin mới từ đánh giá lại thường\nquy hoặc có thể thấy rõ từ sự thay đổi đột ngột về tình trạng của bệnh nhân. Kế hoạch chăm sóc được sửa đổi dựa\ntrên những thay đổi này và được ghi lại trong hồ sơ y tế dưới dạng ghi chú cho kế hoạch ban đầu hoặc dưới dạng\nkế hoạch chăm sóc được sửa đổi hoặc mới.","m":[{"t":"Tất cả các dịch vụ, điều trị và chăm sóc hậu phẫu đều đáp ứng nhu cầu hậu phẫu tức thời của bệnh nhân.","b":[]},{"t":"Kế hoạch hậu phẫu liên tục được ghi lại trong hồ sơ y tế của bệnh nhân trong vòng 24 giờ bởi bác sĩ phẫu thuật chịu trách nhiệm hoặc được xác minh bằng chữ ký chung của bác sĩ phẫu thuật chịu trách nhiệm trên kế hoạch được ghi lại do người được bác sĩ phẫu thuật ủy quyền nhập.","b":[]},{"t":"Kế hoạch chăm sóc hậu phẫu liên tục bao gồm dịch vụ chăm sóc, điều trị và các dịch vụ dựa trên nhu cầu được đánh giá của bệnh nhân.","b":[]},{"t":"Khi có chỉ định thay đổi về nhu cầu của bệnh nhân, kế hoạch chăm sóc hậu phẫu sẽ được cập nhật hoặc sửa đổi dựa trên việc đánh giá lại bệnh nhân của các bác sĩ chăm sóc sức khỏe. (Xem thêm COP.01.01, ME 3)","b":[]}],"sec":"Chăm sóc sau phẫu thuật"},{"c":"ASC.04.04","ch":"ASC","t":"Chăm sóc phẫu thuật bao gồm cấy ghép thiết bị y tế được lên kế hoạch với sự cân nhắc đặc biệt về cách thức phải sửa đổi các quy trình tiêu chuẩn.","p":"Các thủ thuật phẫu thuật liên quan đến việc cấy ghép thiết bị y tế đòi hỏi phải điều chỉnh việc chăm sóc phẫu thuật thông\nthường để tính đến các yếu tố đặc biệt. Các thủ thuật phẫu thuật liên quan đến việc cấy ghép thiết bị y tế là phổ biến đối\nvới nhiều chuyên khoa y tế. Thiết bị y tế đã trở thành thành phần quan trọng của chăm sóc sức khỏe,\n\n( SC)\n\nGây mê và chăm sóc\nphẫu thuật (ASC)\nkhông chỉ ở tác động của chúng đối với bệnh tật và tử vong của bệnh nhân mà còn ở khả năng kéo dài chất\nlượng cuộc sống của bệnh nhân. Thiết bị y tế cấy ghép được định nghĩa là thiết bị được đặt vào khoang cơ\nthể được tạo thành tự nhiên hoặc phẫu thuật để liên tục hỗ trợ, phục hồi hoặc thay thế chức năng hoặc cấu\ntrúc của cơ thể; cung cấp thuốc; hoặc theo dõi chức năng cơ thể trong suốt vòng đời hữu ích của thiết bị.\nNhững cân nhắc đặc biệt này có thể được đưa vào các hướng dẫn, giao thức, chính sách vận hành hoặc các\ntài liệu khác để hướng dẫn nhóm phẫu thuật và tạo điều kiện cho các quy trình và kết quả nhất quán.\n\nThiết bị y tế cấy ghép có thể là một bộ phận giả (như hông), một stent, một máy khử rung tim, máy tạo\nnhịp tim, thấu kính nội nhãn hoặc một máy bơm truyền dịch, trong số các ví dụ khác. Khả năng theo dõi các\nthiết bị y tế cấy ghép là điều cần thiết để theo dõi các trường hợp nhiễm trùng tại vị trí phẫu thuật và xác\nđịnh những bệnh nhân có thể đã được cấy ghép không vô trùng. Ngoài ra, quy trình theo dõi cho phép bệnh\nviện đánh giá độ tin cậy của quy trình khử trùng. Do đó, bệnh viện có một quy trình theo dõi các thiết bị y\ntế cấy ghép.\n\nTrong trường hợp thu hồi thiết bị y tế cấy ghép, bệnh viện sẽ thông báo và theo dõi những bệnh nhân đã\nnhận thiết bị. Bệnh viện xây dựng và triển khai một quy trình để liên hệ và theo dõi bệnh nhân, bao gồm cả\nnhững bệnh nhân có thể ở nước ngoài. Bệnh viện xác định khung thời gian để liên hệ với bệnh nhân (ví dụ:\ntrong vòng 24 giờ kể từ thông báo thu hồi chính thức đối với thiết bị cứu sinh). Khung thời gian này có thể\ndài hơn đối với thiết bị không cứu sinh. Bệnh nhân nhận được thông tin về thiết bị cấy ghép như mã định\ndanh thiết bị duy nhất, cách thức hỗ trợ theo dõi thiết bị trong thời gian dài, quy trình thông báo trong\ntrường hợp thiết bị có vấn đề và giáo dục về cách chia sẻ thông tin thiết bị hỗ trợ chăm sóc sức khỏe dài hạn\ncủa bệnh nhân, giám sát an toàn và nghiên cứu trong tương lai để thúc đẩy các hoạt động thực hành và\nan toàn cho bệnh nhân khi sử dụng thiết bị.","m":[{"t":"Các dịch vụ phẫu thuật của bệnh viện xác định các loại thiết bị y tế cấy ghép nằm trong phạm vi dịch vụ của bệnh viện.","b":[]},{"t":"Các chính sách và thực hành được viết ra bao gồm ít nhất những điều sau đây:","b":["Lựa chọn thiết bị dựa trên khoa học và nghiên cứu hiện tại","Xác minh rằng có cấy ghép trong phòng phẫu thuật","Xác minh trình độ và đào tạo của bất kỳ nhân viên kỹ thuật bên ngoài nào được yêu cầu trong quy trình cấy ghép (ví dụ: đại diện của nhà sản xuất có thể được yêu cầu hiệu chỉnh thiết bị)","Quy trình báo cáo các sự cố bất lợi liên quan đến thiết bị cấy ghép","Báo cáo sự cố thiết bị cấy ghép cho các cơ quan quản lý","Các cân nhắc về phòng ngừa và kiểm soát nhiễm trùng duy nhất","Bất kỳ hướng dẫn xuất viện đặc biệt nào cho bệnh nhân"]},{"t":"Bệnh nhân nhận được thông tin về thiết bị cấy ghép bao gồm ít nhất những thông tin sau:","b":["Thông tin nhận dạng trên thiết bị, bao gồm mã định danh thiết bị duy nhất","Cách thức hỗ trợ theo dõi thiết bị trong thời gian dài","Quy trình thông báo trong trường hợp thiết bị có vấn đề","Giáo dục về cách chia sẻ thông tin thiết bị hỗ trợ chăm sóc sức khỏe dài hạn, giám sát an toàn và nghiên cứu trong tương lai của bệnh nhân"]},{"t":"Bệnh viện có quy trình theo dõi thiết bị y tế cấy ghép.","b":[]},{"t":"Bệnh viện thực hiện quy trình liên hệ và theo dõi bệnh nhân trong một khung thời gian xác định sau khi nhận được thông báo thu hồi thiết bị y tế cấy ghép. Chăm sóc bệnh nhân Tổng quan Trách nhiệm quan trọng nhất của một tổ chức chăm sóc sức khỏe và đội ngũ nhân viên là cung cấp dịch vụ chăm sóc an toàn và hiệu quả và các dịch vụ cho tất cả bệnh nhân. Điều này đòi hỏi sự giao tiếp, hợp tác và các quy trình chuẩn hóa hiệu quả để đảm bảo rằng việc lập kế hoạch, phối hợp và triển khai dịch vụ chăm sóc hỗ trợ và đáp ứng các nhu cầu và mục tiêu riêng của từng bệnh nhân. Chăm sóc có thể là phòng ngừa, giảm nhẹ, chữa bệnh hoặc phục hồi chức năng và có thể bao gồm gây mê, phẫu thuật, dùng thuốc, liệu pháp hỗ trợ hoặc kết hợp các phương pháp này và dựa trên việc đánh giá và đánh giá lại từng bệnh nhân. Các lĩnh vực chăm sóc có nguy cơ cao (bao gồm hồi sức, truyền máu, ghép tạng và mô) và chăm sóc cho những nhóm dân số có nguy cơ cao hoặc có nhu cầu đặc biệt cần được quan tâm thêm. Một phần của việc cung cấp dịch vụ chăm sóc cũng bao gồm việc xác định và giảm các yếu tố rủi ro có thể ảnh hưởng đến việc chăm sóc bệnh nhân như các rủi ro liên quan đến những bệnh nhân có thể tự tử hoặc có nguy cơ cao gặp biến chứng do quá trình bệnh lý hoặc phẫu thuật. Chăm sóc bệnh nhân được thực hiện bởi nhiều chuyên khoa và đội ngũ nhân viên hỗ trợ. Tất cả các cá nhân tham gia vào việc chăm sóc bệnh nhân phải có vai trò rõ ràng được xác định theo giấy phép; thông tin xác thực; chứng nhận; luật pháp và quy định; kỹ năng, kiến thức và kinh nghiệm cụ thể của một cá nhân; và chính sách của tổ chức hoặc mô tả công việc. Một số dịch vụ chăm sóc có thể được thực hiện bởi bệnh nhân, gia đình của họ hoặc những người chăm sóc được đào tạo khác. Hỗ trợ bổ sung cũng có thể được cung cấp bởi một hoặc nhiều cá nhân được chỉ định, chẳng hạn như người ủng hộ người hiến tặng còn sống, người có kiến thức về quy trình chăm sóc và có thể tự mình thông báo cho bệnh nhân về mọi cân nhắc có thể ảnh hưởng đến việc ra quyết định. Việc cung cấp dịch vụ chăm sóc và các dịch vụ phải được phối hợp và tích hợp bởi tất cả các cá nhân chăm sóc bệnh nhân. Làm việc cùng với bệnh nhân và gia đình, những cá nhân này đảm bảo rằng các tiêu chí sau được đáp ứng:","b":["Dựa trên đánh giá, dịch vụ chăm sóc được lập kế hoạch để đáp ứng nhu cầu riêng của từng bệnh nhân.","Dịch vụ chăm sóc được lập kế hoạch được cung cấp cho từng bệnh nhân.","Phản ứng của bệnh nhân đối với dịch vụ chăm sóc được theo dõi.","Dịch vụ chăm sóc được lập kế hoạch được sửa đổi khi cần thiết, dựa trên phản ứng của bệnh nhân. Tiêu chuẩn Sau đây là danh sách tất cả các tiêu chuẩn cho chức năng này. Chúng được trình bày ở đây để thuận tiện cho bạn mà không có các tuyên bố ý định hoặc các yếu tố có thể đo lường. Để biết thêm thông tin về các tiêu chuẩn này, vui lòng xem phần tiếp theo trong chương này, Tiêu chuẩn, Ý định và Các yếu tố có thể đo lường. Cung cấp dịch vụ chăm sóc cho tất cả bệnh nhân COP.01.00 Có một quy trình thống nhất để kê đơn và hoàn thành đơn thuốc điều trị. COP.01.01 Một kế hoạch chăm sóc cá nhân được phát triển và ghi chép lại cho từng bệnh nhân. COP.01.02 Việc cung cấp các dịch vụ có rủi ro cao được hướng dẫn bởi các hướng dẫn thực hành chuyên môn, luật pháp và quy định. Quản lý hệ thống báo động lâm sàng COP.02.00 Bệnh viện thực hiện các chính sách và quy trình đảm bảo an toàn cho hệ thống báo động lâm sàng. (C P) Nhận biết những thay đổi về tình trạng bệnh nhân COP.03.00 Đội ngũ nhân viên lâm sàng được đào tạo để nhận biết và ứng phó với những thay đổi về tình trạng của bệnh nhân. Dịch vụ hồi sức COP.04.00 Dịch vụ hồi sức có sẵn trong toàn bệnh viện. Quản lý bệnh nhân có nguy cơ tự tử hoặc tự làm hại bản thân COP.05.00 Bệnh viện có quy trình xác định và bảo vệ bệnh nhân có nguy cơ tự tử và tự làm hại bản thân. Liệu pháp dinh dưỡng và thực phẩm COP.06.00 Thực phẩm, sản phẩm dinh dưỡng và liệu pháp dinh dưỡng có sẵn cho bệnh nhân. Quản lý cơn đau COP.07.00 Cơn đau được kiểm soát hiệu quả. Chăm sóc cuối đời COP.08.00 Bệnh viện có quy trình cung cấp dịch vụ chăm sóc cuối đời đáp ứng nhu cầu của bệnh nhân và gia đình, đồng thời tối ưu hóa sự thoải mái và phẩm giá của bệnh nhân. Bệnh viện cung cấp dịch vụ cấy ghép COP.09.00 Bệnh viện thông báo cho bệnh nhân và gia đình về cách hiến tặng nội tạng và các mô khác. COP.09.01 Bệnh viện cung cấp sự giám sát cho quá trình thu thập nội tạng và mô. COP.09.02 Các nhà lãnh đạo bệnh viện cung cấp nguồn lực để hỗ trợ chương trình ghép tạng, mô và/hoặc tế bào. COP.09.03 Bệnh viện xác định những người lãnh đạo chương trình cấy ghép đủ tiêu chuẩn và bao gồm một nhóm liên ngành bao gồm các nhân viên lâm sàng có chuyên môn về các chương trình cấy ghép có liên quan. COP.09.04 Có một cơ chế phối hợp được chỉ định cho tất cả các hoạt động cấy ghép. COP.09.05 Bệnh viện thực hiện trách nhiệm ghép tạng, mô, tế bào. COP.09.06 Chương trình cấy ghép cần có sự đồng ý có thông tin cụ thể về việc cấy ghép nội tạng, mô và/hoặc tế bào từ ứng viên nhận ghép. COP.09.07 Chương trình cấy ghép đã ghi chép các giao thức, hướng dẫn thực hành lâm sàng hoặc quy trình phục hồi nội tạng và tiếp nhận nội tạng để đảm bảo tính tương thích, an toàn, hiệu quả và chất lượng của tế bào, mô và nội tạng của con người để cấy ghép. COP.09.08 Hướng dẫn thực hành lâm sàng và tiêu chuẩn lâm sàng hướng dẫn việc lựa chọn và chăm sóc bệnh nhân ghép tạng, mô và tế bào. Chương trình cấy ghép sử dụng nội tạng của người hiến tặng còn sống COP.10.00 Các chương trình cấy ghép thực hiện cấy ghép từ người hiến tặng còn sống tuân thủ luật pháp và quy định của địa phương và khu vực và bảo vệ quyền của người hiến tặng tiềm năng hoặc thực tế còn sống. COP.10.01 Các chương trình cấy ghép thực hiện cấy ghép từ người hiến tặng còn sống phải có sự đồng ý được thông báo cụ thể về việc hiến tặng nội tạng từ người hiến tặng còn sống tiềm năng. COP.10.02 Các chương trình cấy ghép thực hiện cấy ghép từ người hiến tặng còn sống sử dụng các tiêu chí lựa chọn về mặt lâm sàng và tâm lý để xác định tính phù hợp của những người hiến tặng còn sống tiềm năng. COP.10.03 Các kế hoạch chăm sóc bệnh nhân được cá nhân hóa hướng dẫn việc chăm sóc những người hiến tặng còn sống. (C P) Cung cấp dịch vụ chăm sóc cho tất cả bệnh nhân"]}],"sec":"Gây mê và chăm sóc"},{"c":"COP.01.00","ch":"COP","t":"Có một quy trình thống nhất để kê đơn và hoàn thành đơn thuốc điều trị.","p":"Một quy trình thống nhất để kê đơn, hoàn thành và ghi chép đơn thuốc của bệnh nhân góp phần vào việc tích hợp\nvà phối hợp các hoạt động chăm sóc bệnh nhân, sử dụng hiệu quả hơn nguồn nhân lực và các nguồn lực khác, và\ntăng khả năng đạt được kết quả tốt hơn cho bệnh nhân.\n\nMỗi thành viên của nhóm chăm sóc sức khỏe đều ghi lại các quan sát và phương pháp điều trị trong hồ sơ y tế\ncủa bệnh nhân. Nhiều hoạt động chăm sóc bệnh nhân yêu cầu một cá nhân đủ điều kiện kê đơn thuốc cho hoạt\nđộng đó. Ví dụ về các hoạt động như vậy bao gồm:\n• Đơn thuốc xét nghiệm\n• Quản lý thuốc\n• Chăm sóc điều dưỡng cụ thể\n• Liệu pháp dinh dưỡng\n• Liệu pháp phục hồi chức năng\nCác đơn thuốc này được ghi lại trong hồ sơ y tế của bệnh nhân và phải dễ dàng truy cập.\n\nGiao tiếp hiệu quả, kịp thời, chính xác, đầy đủ, rõ ràng và được người nhận hiểu, giúp giảm lỗi và cải thiện sự an\ntoàn của bệnh nhân. Giao tiếp có thể là điện tử, bằng lời nói hoặc bằng văn bản. Các trường hợp chăm sóc bệnh\nnhân có thể bị ảnh hưởng nghiêm trọng do giao tiếp kém bao gồm các đơn thuốc chăm sóc bệnh nhân bằng lời nói\nvà qua điện thoại, giao tiếp bằng lời nói và qua điện thoại về kết quả xét nghiệm quan trọng và giao tiếp bàn giao.\n\nLệnh chăm sóc bệnh nhân được đưa ra bằng lời nói trực tiếp và qua điện thoại, nếu được luật pháp và quy định của\nđịa phương cho phép, là một trong những hình thức giao tiếp dễ xảy ra lỗi nhất. Các giọng, phương ngữ và cách\nphát âm khác nhau có thể khiến người nhận khó hiểu được lệnh được đưa ra. Ví dụ, tên thuốc và số thuốc phát âm\ngiống nhau, chẳng hạn như erythromycin và azithromycin hoặc mười lăm và năm mươi, có thể ảnh hưởng đến độ\nchính xác của lệnh. Tiếng ồn xung quanh, sự gián đoạn và tên thuốc và thuật ngữ không quen thuộc thường làm\ntrầm trọng thêm vấn đề. Khi nhận được, lệnh bằng lời nói phải được phiên âm thành lệnh bằng văn bản, điều này\nlàm tăng thêm sự phức tạp và rủi ro cho quá trình ra lệnh.\n\nCác thủ thuật và phương pháp điều trị lâm sàng và chẩn đoán được thực hiện đều được ghi lại trong hồ sơ bệnh\nán của bệnh nhân. Kết quả hoặc kết quả của bất kỳ phương pháp điều trị hoặc thủ thuật nào đều được ghi lại\ntrong hồ sơ y tế của bệnh nhân. Thông tin về người đã yêu cầu thủ thuật hoặc phương pháp điều trị và chỉ\nđịnh cho thủ thuật hoặc phương pháp điều trị đều được đưa vào hồ sơ.\n\nCác lệnh phải nằm trong một phần được chỉ định của hồ sơ y tế (ví dụ: biểu mẫu yêu cầu ra lệnh trong hồ\nsơ bệnh án bản cứng hoặc phần nhập lệnh của hồ sơ sức khỏe điện tử). Không nên xen kẽ chúng trong nhiều\nphần khác nhau của hồ sơ y tế (ví dụ: biểu mẫu yêu cầu đặt hàng và ghi chú tiến trình), vì điều này làm tăng\nkhả năng bỏ sót đơn hàng. Các biện pháp an toàn để truyền đạt đơn hàng và kết quả xét nghiệm bao gồm:\n•\nHạn chế việc truyền đạt đơn thuốc hoặc đơn thuốc bằng lời nói trong các tình huống khẩn cấp mà không\nthể truyền đạt ngay bằng văn bản hoặc điện tử. Ví dụ, có thể không cho phép truyền đạt đơn thuốc bằng\nlời nói khi có mặt bác sĩ kê đơn và có biểu đồ bệnh nhân. Có thể hạn chế truyền đạt đơn thuốc bằng lời\nnói trong các tình huống mà việc truyền đạt đơn thuốc bằng bản cứng hoặc điện tử là khó hoặc không thể,\nchẳng hạn như trong quá trình vô trùng.\n\n(C P)\n\n•\nViệc xây dựng các hướng dẫn để yêu cầu và nhận kết quả xét nghiệm trong trường hợp khẩn cấp hoặc theo\nquy định, việc xác định và định nghĩa các xét nghiệm quan trọng và các giá trị quan trọng, kết quả xét nghiệm\nquan trọng được báo cáo cho ai và bởi ai, và giám sát việc tuân thủ.\n•\nViết ra hoặc nhập vào máy tính toàn bộ lệnh hoặc kết quả xét nghiệm của người nhận thông tin;\nsử dụng giao tiếp vòng kín với người nhận đọc lại lệnh hoặc kết quả xét nghiệm; và người gửi xác\nnhận rằng những gì đã được viết ra và đọc lại là chính xác. Có thể xác định các phương án thay thế\nđược phép khi quá trình đọc lại không phải lúc nào cũng khả thi, chẳng hạn như trong phòng phẫu\nthuật và trong các tình huống khẩn cấp tại khoa cấp cứu hoặc khoa chăm sóc đặc biệt.","m":[{"t":"Bệnh viện thực hiện một quy trình thống nhất bằng văn bản để kê đơn thuốc cho bệnh nhân bao gồm các nội dung sau:","b":["Thông tin cần thiết trong đơn hàng","Xác định các lệnh có thể được nhận bằng lời nói, qua điện thoại và qua tin nhắn (Xem thêm MMU.04.01, ME 6)","Ai đủ điều kiện và được phép kê đơn thuốc cho bệnh nhân (Xem thêm MMU.04.00, ME 1)","Cách thức và địa điểm các đơn hàng được ghi chép thống nhất trong hồ sơ y tế của bệnh nhân","Nhân viên nào được phép tiếp nhận và ghi lại các lệnh bằng lời nói, điện thoại và tin nhắn theo luật pháp và quy định?","Khung thời gian mà các đơn thuốc bằng lời nói, điện thoại và tin nhắn phải được người kê đơn ký"]},{"t":"Các lệnh chẩn đoán hình ảnh và xét nghiệm lâm sàng bao gồm chỉ định/cơ sở lâm sàng khi cần giải thích.","b":[]},{"t":"Các lệnh bằng lời hoàn chỉnh, bao gồm cả lệnh qua điện thoại, đều được ghi lại và đọc lại bởi người nhận và được xác nhận bởi người ra lệnh.","b":[]},{"t":"Các thủ thuật và phương pháp điều trị được thực hiện theo chỉ định và được ghi lại trong hồ sơ y tế của bệnh nhân.","b":[]},{"t":"Kết quả của các thủ thuật và phương pháp điều trị được thực hiện được ghi lại trong hồ sơ y tế của bệnh nhân. (Xem thêm ASC.03.02, ME 3)","b":[]},{"t":"Kết quả xét nghiệm được báo cáo bằng lời nói được ghi lại và đọc lại bởi người nhận và được xác nhận bởi cá nhân đưa ra kết quả xét nghiệm.","b":[]}],"sec":"Cung cấp dịch vụ chăm sóc cho tất cả bệnh nhân"},{"c":"COP.01.01","ch":"COP","t":"Một kế hoạch chăm sóc cá nhân được phát triển và ghi chép lại cho từng bệnh nhân.","p":"Kế hoạch chăm sóc nêu rõ việc chăm sóc, điều trị và các dịch vụ sẽ được cung cấp cho từng bệnh nhân. Mục tiêu\nchung của kế hoạch chăm sóc là đạt được kết quả lâm sàng tối ưu. Quá trình lập kế hoạch là quá trình hợp tác và sử\ndụng dữ liệu từ đánh giá ban đầu và đánh giá lại do các thành viên trong nhóm chăm sóc sức khỏe thực hiện để xác\nđịnh và\nưu tiên việc chăm sóc, điều trị và các dịch vụ cần thiết để đáp ứng nhu cầu của bệnh nhân. Bệnh nhân và gia đình\ntham gia vào quá trình lập kế hoạch với nhóm chăm sóc sức khỏe.\n\nKế hoạch chăm sóc được lập trong vòng 24 giờ sau khi nhập viện với tư cách là bệnh nhân nội trú và được cập nhật\nkhi cần thiết để phản ánh tình trạng tiến triển của bệnh nhân. Kế hoạch chăm sóc được ghi lại trong hồ sơ y tế\ncủa bệnh nhân.\n\nKế hoạch chăm sóc cho bệnh nhân phải liên quan đến nhu cầu đã xác định của họ. Nhu cầu của bệnh nhân có thể\nthay đổi do cải thiện lâm sàng hoặc thông tin mới từ quá trình đánh giá lại thường quy (ví dụ: kết quả xét nghiệm\nhoặc chụp X-quang bất thường) hoặc có thể thấy rõ từ sự thay đổi về tình trạng của bệnh nhân (ví dụ: mất\ný thức). Kế hoạch chăm sóc được sửa đổi dựa trên những thay đổi này và được ghi lại trong hồ sơ y tế dưới dạng\nghi chú cho kế hoạch ban đầu hoặc dưới dạng kế hoạch chăm sóc mới.\n\n(C P)\n\nMột phương pháp để xây dựng kế hoạch chăm sóc là xác định và thiết lập các mục tiêu có thể đo lường được. Các mục\ntiêu có thể đo lường được có thể được bác sĩ chịu trách nhiệm cùng với y tá và các thành viên khác trong nhóm chăm\nsóc sức khỏe lựa chọn. Các mục tiêu có thể đo lường được là các mục tiêu có thể quan sát được, có thể đạt được liên\nquan đến việc chăm sóc bệnh nhân và kết quả lâm sàng mong đợi.\n\nCác mục tiêu phải thực tế, cụ thể đối với bệnh nhân và dựa trên thời gian để cung cấp phương tiện đo lường tiến trình và\nkết quả liên quan đến kế hoạch chăm sóc. Các ví dụ về các mục tiêu có thể đo lường được, thực tế bao gồm:\n•\nBệnh nhân sẽ tiếp tục và duy trì lưu lượng tim đầy đủ như được chỉ ra bởi nhịp tim, nhịp điệu và huyết áp trong\ngiới hạn bình thường.\n•\nBệnh nhân sẽ chứng minh được cách tự tiêm insulin đúng cách trước khi xuất viện.\n•\nBệnh nhân sẽ có thể đi từ giường đến phòng chờ dành cho khách bằng một chiếc xe tập đi tiêu chuẩn, chịu trọng\nlượng ở mức có thể chịu được trên chân bị ảnh hưởng.\nLưu ý: Một kế hoạch chăm sóc duy nhất, tích hợp xác định các mục tiêu có thể đo lường được mà mỗi bác sĩ chăm sóc\nsức khỏe mong đợi là tốt nhất. Thực hành tốt là kế hoạch chăm sóc phải phản ánh các mục tiêu cá nhân, khách quan và\ncó thể đo lường được để tạo điều kiện đánh giá lại và sửa đổi kế hoạch chăm sóc.\n\nMột số khoa có thể tổ chức các hội nghị chăm sóc bệnh nhân đa ngành cho những bệnh nhân đang nhận dịch vụ chăm\nsóc phức tạp từ nhiều dịch vụ. Ví dụ về những bệnh nhân như vậy bao gồm:\n•\nBệnh nhân đang nhận dịch vụ phục hồi chức năng\n•\nBệnh nhân được chẩn đoán nhiều bệnh trong các đơn vị chăm sóc đặc biệt\n•\nBệnh nhân có nhu cầu lập kế hoạch xuất viện phức tạp\n\nMọi kết quả hoặc kết luận từ các cuộc họp nhóm chăm sóc bệnh nhân hợp tác hoặc các cuộc thảo luận tương tự với bệnh\nnhân đều được ghi vào hồ sơ y tế của bệnh nhân.","m":[{"t":"Việc chăm sóc cho mỗi bệnh nhân được bác sĩ, y tá và các thành viên khác trong nhóm chăm sóc sức khỏe lên kế hoạch trong vòng 24 giờ sau khi nhập viện.","b":[]},{"t":"Kế hoạch chăm sóc được cá nhân hóa dựa trên dữ liệu đánh giá ban đầu của bệnh nhân và các nhu cầu đã xác định và được ghi lại trong hồ sơ y tế của bệnh nhân.","b":[]},{"t":"Kế hoạch chăm sóc được cập nhật hoặc sửa đổi dựa trên bất kỳ thay đổi nào về tình trạng của bệnh nhân và được ghi lại trong hồ sơ y tế của bệnh nhân. (Xem thêm AOP.01.05, ME 1; ASC.04.03, ME 4)","b":[]},{"t":"Kết quả hoặc kết luận của bất kỳ cuộc họp nhóm chăm sóc bệnh nhân hoặc các cuộc thảo luận hợp tác khác đều được ghi lại trong hồ sơ y tế của bệnh nhân.","b":[]}],"sec":"Cung cấp dịch vụ chăm sóc cho tất cả bệnh nhân"}];})(window);
